  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Saidah', 'saidah', false, 'Amsterdam-based with London roots, SAIDAH takes inspiration from the birthplace of UKG to bring high energy and bass to every dancefloor she touches. Combining dance music classics with underground releases, she aims to open up the UK scene to new audiences with a fresh sound and perspective.

					She currently holds a radio residency at Amsterdam''s Radio Radio FM where she hosts her bi-monthly show ''sweet like chocolate'' focused on dance music soundscapes in and around the garage genre. Having established herself in Amsterdam''s underground club scene, she''s since delivered her take on UK club music to audiences ranging from Lowlands festival in the Netherlands all the way to Modular in Cape Town.', 'https://www.awakenings.com/en/artists/saidah/380276/', 'festival:awakenings-festival-2026', 'Amsterdam-based with London roots, SAIDAH takes inspiration from the birthplace of UKG to bring high energy and bass to every dancefloor she touches. Combining dance music classics with underground releases, she aims to open up the UK scene to new audiences with a fresh sound and perspective.

					She currently holds a radio residency at Amsterdam''s Radio Radio FM where she hosts her bi-monthly show ''sweet like chocolate'' focused on dance music soundscapes in and around the garage genre. Having established herself in Amsterdam''s underground club scene, she''s since delivered her take on UK club music to audiences ranging from Lowlands festival in the Netherlands all the way to Modular in Cape Town.')
