  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Pegassi', 'pegassi', false, 'Pegassi is the creative alter ego of Sam Huybrecht, an electronic music producer from Belgium, whose genre-defying sound is pushing the boundaries of eurodance, trance, techno and house. Pegassi’s journey to the forefront of the electronic music scene began with his remix of ‘No Type’, which shot to #1 on Soundcloud’s global charts, marking the start of a rapid rise.His breakout club anthem ‘Yoyoyo’ continues to ignite dance floors worldwide, becoming a favorite among many of the scene’s top artists. Pegassi’s bold, energetic productions, spanning a wide array of genres, have garnered support from key tastemakers likeMarlon Hoffstadt, Anetha, Trym, Bad Boombox, Malugi, Job Jobse, VTSS, Solomun, and many more. Recently, Pegassi collaborated with DJIP on the well-received track ‘Wanna Feel’, and fans eagerly await his highly anticipated release ‘No Go Zone’, featuringDutch hip-hop icon Bokoesam. Pegassi has performed at some of Europe’s most iconic venues and festivals, including Thuishaven, Mondo Disko, Junkyard, RSO, Tomorrowland, Else,Intercell, Modul’air, BCCO, Teletech, and a memorable Boiler Room broadcast that has garnered widespread attention.Beyond his success as a performer, Pegassi has launched his own event series and label, Sweet Nothing, through which he plans to tour the world while releasing music from up-and-coming talents. With major projects on the horizon and his unique ability to blend genres, Pegassi is poised to leave an indelible mark on the global electronic music landscape.', 'https://www.awakenings.com/en/artists/pegassi/367230/', 'festival:awakenings-festival-2026', 'Pegassi is the creative alter ego of Sam Huybrecht, an electronic music producer from Belgium, whose genre-defying sound is pushing the boundaries of eurodance, trance, techno and house. Pegassi’s journey to the forefront of the electronic music scene began with his remix of ‘No Type’, which shot to #1 on Soundcloud’s global charts, marking the start of a rapid rise.His breakout club anthem ‘Yoyoyo’ continues to ignite dance floors worldwide, becoming a favorite among many of the scene’s top artists. Pegassi’s bold, energetic productions, spanning a wide array of genres, have garnered support from key tastemakers likeMarlon Hoffstadt, Anetha, Trym, Bad Boombox, Malugi, Job Jobse, VTSS, Solomun, and many more. Recently, Pegassi collaborated with DJIP on the well-received track ‘Wanna Feel’, and fans eagerly await his highly anticipated release ‘No Go Zone’, featuringDutch hip-hop icon Bokoesam. Pegassi has performed at some of Europe’s most iconic venues and festivals, including Thuishaven, Mondo Disko, Junkyard, RSO, Tomorrowland, Else,Intercell, Modul’air, BCCO, Teletech, and a memorable Boiler Room broadcast that has garnered widespread attention.Beyond his success as a performer, Pegassi has launched his own event series and label, Sweet Nothing, through which he plans to tour the world while releasing music from up-and-coming talents. With major projects on the horizon and his unique ability to blend genres, Pegassi is poised to leave an indelible mark on the global electronic music landscape.')
