  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Funk Tribu', 'funk tribu', false, 'Funk Tribu is a producer and DJ from Colombia, based in Berlin. His music is highly influenced by the electronic sound of the 90s & ''00s, creating a retro-futuristic atmosphere. Since his mega hit ‘Phonky Tribu’, Funk Tribu is known for shaping the groovy trance sound nowadays with his genre-fluid productions. You can find his work on renown labels like Speedmaster Records, KTK, Taapion, Color, A Million, Terminal V, Teletech and many more.', 'https://www.awakenings.com/en/artists/funk-tribu/288697/', 'festival:awakenings-festival-2026', 'Funk Tribu is a producer and DJ from Colombia, based in Berlin. His music is highly influenced by the electronic sound of the 90s & ''00s, creating a retro-futuristic atmosphere. Since his mega hit ‘Phonky Tribu’, Funk Tribu is known for shaping the groovy trance sound nowadays with his genre-fluid productions. You can find his work on renown labels like Speedmaster Records, KTK, Taapion, Color, A Million, Terminal V, Teletech and many more.')
