  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Amelie Lens', 'amelie lens', false, 'Amelie Lens is DJ, Producer and label boss whose name has grown synonymous with techno today. The Antwerp native exploded onto the scene as a result of a long-standing love affair with music, earning her first residency at Labyrinth Belgium in 2014. Fast forward to 2023 and Amelie is heading her labels Lenske &EXHALE Records, running her party series EXHALE, hosting her own radio show ‘Amelie Lens presentsEXHALE’, and holding down an extensive global touring schedule. Amelie’s journey began in Antwerp, running her own parties and DJing under numerous aliases. Her debut release came on Italian imprint Lyase, and soon after a trio of releases on Pan-Pot’s SecondState gave her recognition on a global level. As of today, Amelie has contributed to the acclaimed GlobalUnderground City mix series, joining fellow trailblazers of the industry including John Digweed, Sasha &Darren Emerson. She regularly headlines festivals including Awakenings, Sonar and Timewarp, as well as playing up to six gigs per week at revered clubs including Rex, Mondo Disko, fabric, Printworks, and more. Since its inception in 2018, her Lenske label has homed releases from techno trailblazers Farrago, AIRODand Ahl Iver, with her second label Exhale Records being a dedicated platform to give to aspiring producers. Her long-standing EXHALE event series has grown considerably in recent years, with sold-out shows in Antwerp, Printworks London, Awakenings’ ADE edition and residency at Ibiza’s DC-10. The party series continues to grow over 2023 with its US debut as well as a Spring EU/UK tour. Following her special 4-hour essential mix for BBC, the success of her Radio 1 residency and extension in 2020, Amelie continues to establish herself as one of techno’s luminaries with the introduction of her weekly radio show ‘Amelie Lens presents Exhale’, streaming online and broadcasting on 34 radio stations across the globe.', 'https://www.awakenings.com/en/artists/amelie-lens/68/', 'festival:awakenings-festival-2026', 'Amelie Lens is DJ, Producer and label boss whose name has grown synonymous with techno today. The Antwerp native exploded onto the scene as a result of a long-standing love affair with music, earning her first residency at Labyrinth Belgium in 2014. Fast forward to 2023 and Amelie is heading her labels Lenske &EXHALE Records, running her party series EXHALE, hosting her own radio show ‘Amelie Lens presentsEXHALE’, and holding down an extensive global touring schedule. Amelie’s journey began in Antwerp, running her own parties and DJing under numerous aliases. Her debut release came on Italian imprint Lyase, and soon after a trio of releases on Pan-Pot’s SecondState gave her recognition on a global level. As of today, Amelie has contributed to the acclaimed GlobalUnderground City mix series, joining fellow trailblazers of the industry including John Digweed, Sasha &Darren Emerson. She regularly headlines festivals including Awakenings, Sonar and Timewarp, as well as playing up to six gigs per week at revered clubs including Rex, Mondo Disko, fabric, Printworks, and more. Since its inception in 2018, her Lenske label has homed releases from techno trailblazers Farrago, AIRODand Ahl Iver, with her second label Exhale Records being a dedicated platform to give to aspiring producers. Her long-standing EXHALE event series has grown considerably in recent years, with sold-out shows in Antwerp, Printworks London, Awakenings’ ADE edition and residency at Ibiza’s DC-10. The party series continues to grow over 2023 with its US debut as well as a Spring EU/UK tour. Following her special 4-hour essential mix for BBC, the success of her Radio 1 residency and extension in 2020, Amelie continues to establish herself as one of techno’s luminaries with the introduction of her weekly radio show ‘Amelie Lens presents Exhale’, streaming online and broadcasting on 34 radio stations across the globe.')
  ON CONFLICT (sort_name) DO UPDATE SET
