  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Olive Anguz', 'olive anguz', false, 'Olive Anguz is a 21-year-old DJ and Producer blending bouncy, house-driven grooves with subtle trancy energy. 

British at heart but shaped by growing up in the Netherlands, her sound is influenced by time spent in European festivals and club spaces. 

Playful rhythms, forward motion and a sense of lift run through her sets, always focused on feel rather than formula. 

Olive Anguz is about movement, connection, and keeping things light while still hitting deep.', 'https://www.awakenings.com/en/artists/olive-anguz/386630/', 'festival:awakenings-festival-2026', 'Olive Anguz is a 21-year-old DJ and Producer blending bouncy, house-driven grooves with subtle trancy energy. 

British at heart but shaped by growing up in the Netherlands, her sound is influenced by time spent in European festivals and club spaces. 

Playful rhythms, forward motion and a sense of lift run through her sets, always focused on feel rather than formula. 

Olive Anguz is about movement, connection, and keeping things light while still hitting deep.')
