  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Upper90', 'upper90', false, 'Australia born, Berlin based artist Upper90 produces energetic emotionally driven music which speaks to a global audience. This distinctive sound has captured the hearts of Dance Music lovers, already having released numerous tracks that have become instant classics. 

His euphoric approach to producing creates a captivating narrative in his DJ Sets, where the blend of his own productions and the best of Hard House and Trance, leaves an unforgettable dance floor experience.

Having recently launched his new label Dance Power, Upper90 embarks on a new chapter as a label owner, marking a milestone in his music career. With events, clothing lines, and more music releases already on the horizon, 2025 is set to be a memorable year.', 'https://www.awakenings.com/en/artists/upper90/376518/', 'festival:awakenings-festival-2026', 'Australia born, Berlin based artist Upper90 produces energetic emotionally driven music which speaks to a global audience. This distinctive sound has captured the hearts of Dance Music lovers, already having released numerous tracks that have become instant classics. 

