  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Serafina', 'serafina', false, 'Serafina discovered her love for music early on and quickly realized its power to move people. In 2023, she began DJing in Hamburg, captivating crowds with her unique blend of Techno and her warm, open energy.', 'https://www.awakenings.com/en/artists/serafina/386088/', 'festival:awakenings-festival-2026', 'Serafina discovered her love for music early on and quickly realized its power to move people. In 2023, she began DJing in Hamburg, captivating crowds with her unique blend of Techno and her warm, open energy.')
