  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Future.666', 'future.666', false, 'BCCO resident and headliner, Future.666, has been a leading force in stripped down, tooly, techno for several years now. Inspired by 90’s rave culture, his pushy and punchy sound powers an intense, sweaty and sexy set.', 'https://www.awakenings.com/en/artists/future-666/285490/', 'festival:awakenings-festival-2026', 'BCCO resident and headliner, Future.666, has been a leading force in stripped down, tooly, techno for several years now. Inspired by 90’s rave culture, his pushy and punchy sound powers an intense, sweaty and sexy set.')
