    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Überkikz', 'überkikz', false, 'ÜBERKIKZ’s style is inspired by the techno of the late 90s early 2000s. Old treasures from the heyday of hard groove are combined with current releases. In this way, the artist creates a unique fusion of old and new. Her sets are characterized by rolling kicks, tooly synths, tribal and folk elements. Her hypnotic storytelling is unique.

Through her music, she gives listeners the opportunity to let go and feel their own origins. She also takes a public stand against sexism, discrimination and racism, as she wants to develop the scene into a more inclusive space. ÜBERKIKZ does this by actively supporting FLINTA* artists and encouraging them to take space in a male-dominated scene.', 'https://www.awakenings.com/en/artists/uberkikz/362066/', 'festival:awakenings-festival-2026', 'ÜBERKIKZ’s style is inspired by the techno of the late 90s early 2000s. Old treasures from the heyday of hard groove are combined with current releases. In this way, the artist creates a unique fusion of old and new. Her sets are characterized by rolling kicks, tooly synths, tribal and folk elements. Her hypnotic storytelling is unique.

Through her music, she gives listeners the opportunity to let go and feel their own origins. She also takes a public stand against sexism, discrimination and racism, as she wants to develop the scene into a more inclusive space. ÜBERKIKZ does this by actively supporting FLINTA* artists and encouraging them to take space in a male-dominated scene.')
  ON CONFLICT (sort_name) DO UPDATE SET
