    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Cloudy', 'cloudy', false, 'Cloudy is quickly becoming one of the brightest rising stars in the techno scene, captivating audiences worldwide with her electrifying fusion of techno styles. Her sound is a unique mix—bouncy, groovy,
yet hard-hitting and unapologetically schranzy.

With each set, she brings a fresh energy that’s impossible to ignore.
Having already taken stages across Europe, the U.S., South America & Australia by storm, she’s made waves
at renowned events like Unreal, Teletech, and Blackworks, cementing her status as a force to be reckoned with.
When Cloudy steps up to the decks, expect nothing short of magic—she’ll set the dancefloor ablaze,
blending sunshine vibes with thunderous beats that leave no one standing still.', 'https://www.awakenings.com/en/artists/cloudy/362051/', 'festival:awakenings-festival-2026', 'Cloudy is quickly becoming one of the brightest rising stars in the techno scene, captivating audiences worldwide with her electrifying fusion of techno styles. Her sound is a unique mix—bouncy, groovy,
