  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Adrián Mills', 'adrián mills', false, 'Adrian Mills aka the spanish loco that will make you dance all night with hard sounds like (Early) hardstyle and hardcore, acid- and hard techno mixed with ghetto elements and crazyvocals. He received his first mixer with just twelve years old, which gave him plenty of timeto develop his unique style and sound. Now 24 years old, his tracks and mixes give off a unique type of energy which immerses thecrowd and fills the dancefloor with power and ADRENALINE! Adrian is resident at the infamous gotec club as well as at the rising event series ADRENALINE in Cologne.', 'https://www.awakenings.com/en/artists/adrian-mills/381919/', 'festival:awakenings-festival-2026', 'Adrian Mills aka the spanish loco that will make you dance all night with hard sounds like (Early) hardstyle and hardcore, acid- and hard techno mixed with ghetto elements and crazyvocals. He received his first mixer with just twelve years old, which gave him plenty of timeto develop his unique style and sound. Now 24 years old, his tracks and mixes give off a unique type of energy which immerses thecrowd and fills the dancefloor with power and ADRENALINE! Adrian is resident at the infamous gotec club as well as at the rising event series ADRENALINE in Cologne.')
  ON CONFLICT (sort_name) DO UPDATE SET
