    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('AAT', 'aat', false, 'AAT is a house DJ from The Hague, quickly rising in the Dutch house scene. After winning the Toffler Talents competition in January 2023, she quickly established herself as one to watch. In just her first year, she shared lineups with names like Enzo Siragusa, Manda Moor, Sidney Charles, Nick Curly, and Luuk van Dijk. 

By her second year, Aat took her sound internationally, touring across Asia with gigs in Bali, Tokyo, Shanghai, and Seoul. Now, she’s a familiar face at top events like Loveland, Thuishaven, Mysteryland, PIV, Free Your Mind, Hush, Boothstock, and eventually chosen as the new Elrow resident DJ of 2025.

Her signature style can be described as groovy house that keeps the crowd moving. She brings an infectious energy, dancing just as hard as the people in front of her.', 'https://www.awakenings.com/en/artists/aat/386662/', 'festival:awakenings-festival-2026', 'AAT is a house DJ from The Hague, quickly rising in the Dutch house scene. After winning the Toffler Talents competition in January 2023, she quickly established herself as one to watch. In just her first year, she shared lineups with names like Enzo Siragusa, Manda Moor, Sidney Charles, Nick Curly, and Luuk van Dijk. 

By her second year, Aat took her sound internationally, touring across Asia with gigs in Bali, Tokyo, Shanghai, and Seoul. Now, she’s a familiar face at top events like Loveland, Thuishaven, Mysteryland, PIV, Free Your Mind, Hush, Boothstock, and eventually chosen as the new Elrow resident DJ of 2025.

Her signature style can be described as groovy house that keeps the crowd moving. She brings an infectious energy, dancing just as hard as the people in front of her.')
