    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('M-high', 'm-high', false, 'M-high is the stage name of young multi-instrumentalist producer Marijn Schiedon from Amsterdam. His quality releases on labels such as PIV for which he recently became A&R are paving the way to a bright future.A natural studio talent, Marijn was involved in successful music projects from a young age. It was not until he found his current sound that M-high was born.Things started to fall into place with his favourite artists supporting his music and labels interested in signing him. M-high’s signature keys and basslines are now in demand. Soon he signed releases on PIV, Meta, Moxy, Key and many others.The young DJ has spent many hours perfecting his craft in front of crowds and delivers solid performances. His sets always contain a heavy dose of unreleased M-high tracks with lots of groove and intricate heart felt solos.With gigs and festivals already confirmed in The Netherlands and UK for 2021, Marijn is ready to take the world by storm.', 'https://www.awakenings.com/en/artists/m-high/368022/', 'festival:awakenings-festival-2026', 'M-high is the stage name of young multi-instrumentalist producer Marijn Schiedon from Amsterdam. His quality releases on labels such as PIV for which he recently became A&R are paving the way to a bright future.A natural studio talent, Marijn was involved in successful music projects from a young age. It was not until he found his current sound that M-high was born.Things started to fall into place with his favourite artists supporting his music and labels interested in signing him. M-high’s signature keys and basslines are now in demand. Soon he signed releases on PIV, Meta, Moxy, Key and many others.The young DJ has spent many hours perfecting his craft in front of crowds and delivers solid performances. His sets always contain a heavy dose of unreleased M-high tracks with lots of groove and intricate heart felt solos.With gigs and festivals already confirmed in The Netherlands and UK for 2021, Marijn is ready to take the world by storm.')
  ON CONFLICT (sort_name) DO UPDATE SET
