    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Sidney Charles', 'sidney charles', false, 'Sidney Charles has mastered the art of high impact house music that comes with a signature sense of depth, melody and groove. That unique style has made the Hamburg-born DJ, producer and label boss one of the underground''s most prominent names: 2025 has been his busiest ever year with multiple chart-topping releases, high profile support from Radio 1 and standout gigs across the world. Widely regarded as one of House Music’s most trusted tastemakers, Sidney Charles steps into 2026 poised for his biggest year to date.

2025 has proved another standout year in Sidney´s’ ongoing journey, across his global touring and his music releases, known for his rugged sound design and club-ready energy.

His catalogue, from “Space Bass” to “Reso Riddim”, Trip Advisor (rhythm snare bass), has defined a corner of modern house with his unmistakable style: raw, rhythmic, punchy, and built for the dancefloor. with a style rooted in raw groove, deep basslines, and rhythmic sophistication.

Over the last year Sidney has performed at major festivals and venues around the world, EDC Mexico,Space Terrace Miami, Paradise Festival London, Amnesia Closing Party Ibiza, WHP Manchester, Fabrik Madrid, Thuishaven Amsterdam, Sunwaves Festival, Metamorfosi Hi Ibiza, Paradise New York, Creamfields Liverpool, Eastenderz Street Party Manchester, You & Me Factory Town Miami, Paradise Universe Ibiza, Navy Pier w/ Carl Cox (arc) Chicago, Drumsheds London, Amnesia Milan, Mute Mar del Plata, Pyramid Amnesia Ibiza, Coco Rico w/ Chris Stussy Italy, Illuzion Phuket, , Sonora Garden Sao Paulo where music has captured the essence of classic dancefloor energy, while pushing modern boundaries. 

As the curator of Heavy House Society, his label is at the top of the charts in his genre, and is a benchmark for groove-led, dj-focused music, championing the next generation while staying true to its roots, with sold out label parties toured across major cities in the UK, Europe and US including Shelter Amsterdam, Input Barcelona, Fabric London, Nowhere Manchester, Mint Warehouse Leeds, District Cardiff, Silo New York, The Cut Austin, Texas, House Calls Chicago, Floyd Miami, Caposile Venice.

Whether playing to a close and compact crowd in a small basement, or tearing up a vast festival main stage, Sidney knows how to join the dots between the past and the present. He manages to open up new house worlds with his educated selections but never forgets to blow up the dance floor in the process. Just like his productions, his DJ sets are full of surprises, twists and turns but also rooted in physical grooves. His love of jazz, hip hop and funk and his vast knowledge of the 90s sounds always shine through, with plenty of heavy bass which makes the Sidney Sound so irresistible.', 'https://www.awakenings.com/en/artists/sidney-charles/386514/', 'festival:awakenings-festival-2026', 'Sidney Charles has mastered the art of high impact house music that comes with a signature sense of depth, melody and groove. That unique style has made the Hamburg-born DJ, producer and label boss one of the underground''s most prominent names: 2025 has been his busiest ever year with multiple chart-topping releases, high profile support from Radio 1 and standout gigs across the world. Widely regarded as one of House Music’s most trusted tastemakers, Sidney Charles steps into 2026 poised for his biggest year to date.

2025 has proved another standout year in Sidney´s’ ongoing journey, across his global touring and his music releases, known for his rugged sound design and club-ready energy.

His catalogue, from “Space Bass” to “Reso Riddim”, Trip Advisor (rhythm snare bass), has defined a corner of modern house with his unmistakable style: raw, rhythmic, punchy, and built for the dancefloor. with a style rooted in raw groove, deep basslines, and rhythmic sophistication.

Over the last year Sidney has performed at major festivals and venues around the world, EDC Mexico,Space Terrace Miami, Paradise Festival London, Amnesia Closing Party Ibiza, WHP Manchester, Fabrik Madrid, Thuishaven Amsterdam, Sunwaves Festival, Metamorfosi Hi Ibiza, Paradise New York, Creamfields Liverpool, Eastenderz Street Party Manchester, You & Me Factory Town Miami, Paradise Universe Ibiza, Navy Pier w/ Carl Cox (arc) Chicago, Drumsheds London, Amnesia Milan, Mute Mar del Plata, Pyramid Amnesia Ibiza, Coco Rico w/ Chris Stussy Italy, Illuzion Phuket, , Sonora Garden Sao Paulo where music has captured the essence of classic dancefloor energy, while pushing modern boundaries. 

As the curator of Heavy House Society, his label is at the top of the charts in his genre, and is a benchmark for groove-led, dj-focused music, championing the next generation while staying true to its roots, with sold out label parties toured across major cities in the UK, Europe and US including Shelter Amsterdam, Input Barcelona, Fabric London, Nowhere Manchester, Mint Warehouse Leeds, District Cardiff, Silo New York, The Cut Austin, Texas, House Calls Chicago, Floyd Miami, Caposile Venice.

Whether playing to a close and compact crowd in a small basement, or tearing up a vast festival main stage, Sidney knows how to join the dots between the past and the present. He manages to open up new house worlds with his educated selections but never forgets to blow up the dance floor in the process. Just like his productions, his DJ sets are full of surprises, twists and turns but also rooted in physical grooves. His love of jazz, hip hop and funk and his vast knowledge of the 90s sounds always shine through, with plenty of heavy bass which makes the Sidney Sound so irresistible.')
