  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Cloonee', 'cloonee', false, 'The last few years have been meteoric for Cloonee as a producer." - IHouseU. Following his infectious debut EP on Elrow Music in 2017, Cloonee went on to release on some release on some of the scenes most influential labels, solidifying his break onto the scene and gaining support from major taste-makers including Solardo, Lee Foss & Fisher.

Cloonee continued his rise into 2018 releasing "no-nonsense tech house" - Earmilk, on major labels such as Lee Foss'' Repopulate Mars, Michael Bibi''s Solid Grooves and US powerhouse Desert Hearts.

With an Aus/NZ tour in the making, a regular slot Michael Bibi''s UK tour and many more releases lined up for 2019, the stage is set for Cloonee to continue his rise.', 'https://www.awakenings.com/en/artists/cloonee/386079/', 'festival:awakenings-festival-2026', 'The last few years have been meteoric for Cloonee as a producer." - IHouseU. Following his infectious debut EP on Elrow Music in 2017, Cloonee went on to release on some release on some of the scenes most influential labels, solidifying his break onto the scene and gaining support from major taste-makers including Solardo, Lee Foss & Fisher.

Cloonee continued his rise into 2018 releasing "no-nonsense tech house" - Earmilk, on major labels such as Lee Foss'' Repopulate Mars, Michael Bibi''s Solid Grooves and US powerhouse Desert Hearts.

With an Aus/NZ tour in the making, a regular slot Michael Bibi''s UK tour and many more releases lined up for 2019, the stage is set for Cloonee to continue his rise.')
