  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Wade', 'wade', false, 'Wade has consolidated himself as one of the most influential artists in the global scene of electronic music. With a style of his own that blends energy, groove and a unique connection to the public, he has conquered some of the most important festivals worldwide like Tomorrowland, Ultra Miami, Rock in Rio (Rio de Janeiro), EDC, Kappa Futur Festival, Sonus (Croacia), Music On Festival (Amsterdam) or AMF Festival. On top of it all, he has taken his music to the most legendary clubs in the international scene, with highlighted shows in Ushuaïa Ibiza, Hï Ibiza, Pacha or Amnesia.', 'https://www.awakenings.com/en/artists/wade/381978/', 'festival:awakenings-festival-2026', 'Wade has consolidated himself as one of the most influential artists in the global scene of electronic music. With a style of his own that blends energy, groove and a unique connection to the public, he has conquered some of the most important festivals worldwide like Tomorrowland, Ultra Miami, Rock in Rio (Rio de Janeiro), EDC, Kappa Futur Festival, Sonus (Croacia), Music On Festival (Amsterdam) or AMF Festival. On top of it all, he has taken his music to the most legendary clubs in the international scene, with highlighted shows in Ushuaïa Ibiza, Hï Ibiza, Pacha or Amnesia.')
