  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Gordo', 'gordo', false, 'Guatemalan-American DJ and record producer GORDO became one of the most prominent hip hop stars in the world. He played every major club and festival and dominated the charts for years… but then took a risk and switched up his sound! After the pandemic he remerged as Carnage with a new house and tech focus that has quickly seen him reach even higher heights, including co-production credits on the recent Drake album. During this exclusive talk, the man himself talks about his incredible musical evolution with no doubt plenty of behind the scenes stories.', 'https://www.awakenings.com/en/artists/gordo/380102/', 'festival:awakenings-festival-2026', 'Guatemalan-American DJ and record producer GORDO became one of the most prominent hip hop stars in the world. He played every major club and festival and dominated the charts for years… but then took a risk and switched up his sound! After the pandemic he remerged as Carnage with a new house and tech focus that has quickly seen him reach even higher heights, including co-production credits on the recent Drake album. During this exclusive talk, the man himself talks about his incredible musical evolution with no doubt plenty of behind the scenes stories.')
