    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Helsloot', 'helsloot', false, 'Helsloot aka Thomas Helsloot is a dutch based producer / artist known for his futuristic and heavily hip hop influenced take on techno and disco.

After a decade of working behind the scenes, Dutch based producer Thomas Helsloot, needed an outlet and deep dove into his own preference for progressive, house, disco and techno. This resulted in the start of Helsloot, a refreshing combination of introspective and futuristic productions which reflects the person behind his last name perfectly. 

Helsloot became a serious project instead of just being an outlet for his own musical inspiration. The first bunch of Helsloot productions included a draft of ‘Because You Move Me’ which he sent to his producer buddies Tinlicker right before their breakthrough. After releasing it on Armada ‘Because You Move Me’ has gained over 260 million streams and went gold in Germany, France, Canada, Austria and Switzerland.

This gave him the chance to step into the spotlight as a DJ and finetune his sets with own productions. This resulted in the track ‘Let’s Pretend’ which was released on Get Physical. Next to Eelke Kleijn and Colyn, Maceo Plex picked it up and played it in every set during his summer 2022 tour. Not long after the collab ‘Open The Gate’ with friends Goom Gum came out on Ritter Butzke which was played by Solomun during his 2022 closing party in Ibiza.

Helsloot also released tracks on other imprints like Anjunadeep, Domino, Astralwerks and Poesie Musik.', 'https://www.awakenings.com/en/artists/helsloot/394977/', 'festival:awakenings-festival-2026', 'Helsloot aka Thomas Helsloot is a dutch based producer / artist known for his futuristic and heavily hip hop influenced take on techno and disco.

After a decade of working behind the scenes, Dutch based producer Thomas Helsloot, needed an outlet and deep dove into his own preference for progressive, house, disco and techno. This resulted in the start of Helsloot, a refreshing combination of introspective and futuristic productions which reflects the person behind his last name perfectly. 

Helsloot became a serious project instead of just being an outlet for his own musical inspiration. The first bunch of Helsloot productions included a draft of ‘Because You Move Me’ which he sent to his producer buddies Tinlicker right before their breakthrough. After releasing it on Armada ‘Because You Move Me’ has gained over 260 million streams and went gold in Germany, France, Canada, Austria and Switzerland.

This gave him the chance to step into the spotlight as a DJ and finetune his sets with own productions. This resulted in the track ‘Let’s Pretend’ which was released on Get Physical. Next to Eelke Kleijn and Colyn, Maceo Plex picked it up and played it in every set during his summer 2022 tour. Not long after the collab ‘Open The Gate’ with friends Goom Gum came out on Ritter Butzke which was played by Solomun during his 2022 closing party in Ibiza.

Helsloot also released tracks on other imprints like Anjunadeep, Domino, Astralwerks and Poesie Musik.')
