  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('KASIA', 'kasia', false, 'Nestled in the heartbeat of underground scenes, KASIA seamlessly blends raw intensity with deep melancholy, creating a sonic journey teeming with emotions. With roots entrenched in rave culture and a background in drumming, her melodic techno pulses with hypnotic rhythms and ethereal synths, captivating audiences worldwide. Recognized for her talent and positive energy, KASIA has graced stages for industry giants like Afterlife, Drumcode, Tomorrowland, ELROW, and Zamna.

Her productions not only climb the Beatport charts but also garner acclaim from international DJs, solidifying her position as a driving force in the electronic music realm. Since herdebut EP on New Tab, Kasia continues to deliver chart-topping tracks, with her recent release on Drumcode marking another milestone in her illustrious career.', 'https://www.awakenings.com/en/artists/kasia/368215/', 'festival:awakenings-festival-2026', 'Nestled in the heartbeat of underground scenes, KASIA seamlessly blends raw intensity with deep melancholy, creating a sonic journey teeming with emotions. With roots entrenched in rave culture and a background in drumming, her melodic techno pulses with hypnotic rhythms and ethereal synths, captivating audiences worldwide. Recognized for her talent and positive energy, KASIA has graced stages for industry giants like Afterlife, Drumcode, Tomorrowland, ELROW, and Zamna.

Her productions not only climb the Beatport charts but also garner acclaim from international DJs, solidifying her position as a driving force in the electronic music realm. Since herdebut EP on New Tab, Kasia continues to deliver chart-topping tracks, with her recent release on Drumcode marking another milestone in her illustrious career.')
