    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Marco Faraone', 'marco faraone', false, 'As his style developed, Marco became fascinated with the 90s house championed by Masters At Work and Todd Terry, whilst admiring Laurent Garnier for his ability to effortlessly play diverse sets. Developing his production skills led to his first release in 2008, ‘Arabia’ on Tenax Recordings. Although this effort was well received, it took a further few years of hard work and sending out demos before Faraone’s “big break”, with the 2010 EP ‘Strange Neighbors’ on Moon Harbour. When label boss Matthias Tanzmann played the title track out at DC10 in Ibiza, it prompted a huge reaction with a dancefloor sit-down. Marco Faraone had arrived. He’s since developed a worldwide reputation as an extremely skilled producer, with releases ranging from the warm analogue house grooves of his most recent Moon Harbour EP ‘Next Level’, to the relentless, hypnotic techno of his latest EP for On Edge Society, ‘Black Air’. It’s thanks to this versatility that Faraone has released on so many respected labels in a relatively short period of time – Drumcode, Desolat, Be As One, Sci+Tec, Moda Black, Holic Trax, Get Physical and Truesoul have all provided a home for Faraone’s productions.As a DJ, Faraone is equally busy. His popularity back home in Italy is plain to see, with 3 years of a residency and counting under his belt at the famed Tenax club in Florence. Founded in 1981, the club’s 16-year old Saturday night series ‘Nobody’s Perfect’ has played host to the likes of Adam Beyer, Loco Dice, Ricardo Villlalobos, Dixon, Marcel Dettman, Ben Klock, Carl Cox, Nina Kraviz, Solomun and Chris Liebing. Faraone believes “It’s one of the best clubs in the world.” He’s managed to maintain the residency despite his increasingly packed tour schedule across the globe – a selection of recent highlights from his calendar include Belgian super festivals Tomorrowland and Extrema Outdoors, Barcelona’s Elrow, tastemaking US clubs Output, Verboten and Stereo Montreal, and infamous Berlin techno havens Panorama Bar and Watergate, with BPM Mexico on the horizon for 2016. Having earned his stripes as both trusted resident and a travelling headliner, Marco has now launched his own event series in Italy, ‘Marco Faraone and Friends’. The latest edition saw 4000 clubbers invading the beach in Sicily, demonstrating the extent of Faraone’s loyal fanbase at home. With so many high-profile dates behind him and the support of some of the most respected names in electronic music, Faraone is now perfectly placed to begin running his own imprint. Uncage Music will launch on November 16th, with Faraone’s brand new EP ‘Rotaryknobs’. Including an incredible extended Radio Slave remix of the title track and an edit from Markus Suckut, the EP has already been creating plenty of noise and attracting attention online.Marco Faraone is an exceptionally multi-talented young DJ and producer, yet the launch of Uncage shows he is still adding strings to his bow – a sign of true staying power in this fast-paced industry', 'https://www.awakenings.com/en/artists/marco-faraone/940/', 'festival:awakenings-festival-2026', 'As his style developed, Marco became fascinated with the 90s house championed by Masters At Work and Todd Terry, whilst admiring Laurent Garnier for his ability to effortlessly play diverse sets. Developing his production skills led to his first release in 2008, ‘Arabia’ on Tenax Recordings. Although this effort was well received, it took a further few years of hard work and sending out demos before Faraone’s “big break”, with the 2010 EP ‘Strange Neighbors’ on Moon Harbour. When label boss Matthias Tanzmann played the title track out at DC10 in Ibiza, it prompted a huge reaction with a dancefloor sit-down. Marco Faraone had arrived. He’s since developed a worldwide reputation as an extremely skilled producer, with releases ranging from the warm analogue house grooves of his most recent Moon Harbour EP ‘Next Level’, to the relentless, hypnotic techno of his latest EP for On Edge Society, ‘Black Air’. It’s thanks to this versatility that Faraone has released on so many respected labels in a relatively short period of time – Drumcode, Desolat, Be As One, Sci+Tec, Moda Black, Holic Trax, Get Physical and Truesoul have all provided a home for Faraone’s productions.As a DJ, Faraone is equally busy. His popularity back home in Italy is plain to see, with 3 years of a residency and counting under his belt at the famed Tenax club in Florence. Founded in 1981, the club’s 16-year old Saturday night series ‘Nobody’s Perfect’ has played host to the likes of Adam Beyer, Loco Dice, Ricardo Villlalobos, Dixon, Marcel Dettman, Ben Klock, Carl Cox, Nina Kraviz, Solomun and Chris Liebing. Faraone believes “It’s one of the best clubs in the world.” He’s managed to maintain the residency despite his increasingly packed tour schedule across the globe – a selection of recent highlights from his calendar include Belgian super festivals Tomorrowland and Extrema Outdoors, Barcelona’s Elrow, tastemaking US clubs Output, Verboten and Stereo Montreal, and infamous Berlin techno havens Panorama Bar and Watergate, with BPM Mexico on the horizon for 2016. Having earned his stripes as both trusted resident and a travelling headliner, Marco has now launched his own event series in Italy, ‘Marco Faraone and Friends’. The latest edition saw 4000 clubbers invading the beach in Sicily, demonstrating the extent of Faraone’s loyal fanbase at home. With so many high-profile dates behind him and the support of some of the most respected names in electronic music, Faraone is now perfectly placed to begin running his own imprint. Uncage Music will launch on November 16th, with Faraone’s brand new EP ‘Rotaryknobs’. Including an incredible extended Radio Slave remix of the title track and an edit from Markus Suckut, the EP has already been creating plenty of noise and attracting attention online.Marco Faraone is an exceptionally multi-talented young DJ and producer, yet the launch of Uncage shows he is still adding strings to his bow – a sign of true staying power in this fast-paced industry')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
