  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Joris Voorn', 'joris voorn', false, 'Joris Voorn sits at the epicentre of the Dutch dance music scene and is one of Netherlands’ most celebrated globally touring acts. Never sitting still, he is a sophisticated composer and performer of precise, powerful and emotional electronic music. An immaculate producer and artist who stands alone in his unique approach to weaving underground music with carefully placed moments of emotive melody. 

Joris’s attention to detail both in the studio and on stage are unsurpassed and it’s this drive for perfection that sits at the core of his manifesto and which has led to him remixing for many of the scene’s coolest including Dua Lipa, Vintage Culture, Swedish House Mafia, London Grammar, Editors, Underworld, Orbital, Elderbrook, Röyksopp and Groove Armada. 

Joris’s long awaited 5th studio album, SEROTONIN, recently landed on Spectrum / Armada. Following a series of singles that include “You & I” with Nathan Nicholson, “Burn” with Tom Walker, “Seventeen” with Yotto and White Lies, “Flora” with Jan Blomqvist and the most recent single “Utopia” with Goodboys, the album has already amassed wide acclaim from global dance press as well as peers, reaffirming Joris’s position as a true pioneer of melodic techno and house. 

Joris launched his new album with a special sold out party at the very top The Shard, 800 feet above London, and his recent run of SEROTONIN shows in Amsterdam, London, Poland, Barcelona and Miami saw Joris performing live for the first time in 15 years set to a stunning AV visual presentation from LiveFrame (Tale of Us / Timewarp). 

Joris now embarks on his SEROTONIN world tour that will take the album’s euphoric tones to all corners of the planet.', 'https://www.awakenings.com/en/artists/joris-voorn/746/', 'festival:awakenings-festival-2026', 'Joris Voorn sits at the epicentre of the Dutch dance music scene and is one of Netherlands’ most celebrated globally touring acts. Never sitting still, he is a sophisticated composer and performer of precise, powerful and emotional electronic music. An immaculate producer and artist who stands alone in his unique approach to weaving underground music with carefully placed moments of emotive melody. 

Joris’s attention to detail both in the studio and on stage are unsurpassed and it’s this drive for perfection that sits at the core of his manifesto and which has led to him remixing for many of the scene’s coolest including Dua Lipa, Vintage Culture, Swedish House Mafia, London Grammar, Editors, Underworld, Orbital, Elderbrook, Röyksopp and Groove Armada. 

Joris’s long awaited 5th studio album, SEROTONIN, recently landed on Spectrum / Armada. Following a series of singles that include “You & I” with Nathan Nicholson, “Burn” with Tom Walker, “Seventeen” with Yotto and White Lies, “Flora” with Jan Blomqvist and the most recent single “Utopia” with Goodboys, the album has already amassed wide acclaim from global dance press as well as peers, reaffirming Joris’s position as a true pioneer of melodic techno and house. 

Joris launched his new album with a special sold out party at the very top The Shard, 800 feet above London, and his recent run of SEROTONIN shows in Amsterdam, London, Poland, Barcelona and Miami saw Joris performing live for the first time in 15 years set to a stunning AV visual presentation from LiveFrame (Tale of Us / Timewarp). 

Joris now embarks on his SEROTONIN world tour that will take the album’s euphoric tones to all corners of the planet.')
