  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Bullzeye', 'bullzeye', false, 'Starting very young, Bullzeye has been a power to reckon with since 1999. Quickly gaining popularity he became a name every rager spoke about. People loved him and the powerful sets that he always delivered.Been played alongside mighty names such as Carl Cox, Dixon, Oliver Huntemann, Eric Prydz, Nina Kraviz, B2B with Maceo Plex and on big stages like Supersonic, Sunburn, Enchanted Valley Carnival, Krank, Awakenings stage India etc. His doors to Europe opened with warm welcoming hugs. Being the unstoppable force that is, he goes aheadsmashing the floors of Paradiso (Amsterdam), Feel Festival (Berlin), Ritter Butzke (Berlin) Awakenings Festival Afterparty (Amsterdam) and many more.

Also as an Owner of Rage Entertainment , he is out there to make music spoken about religion. One of the most booked DJs in India and the only Indian Dj to play the Ellum audio showcase as an Ellum dj in April in Goa', 'https://www.awakenings.com/en/artists/bullzeye/214052/', 'festival:awakenings-festival-2026', 'Starting very young, Bullzeye has been a power to reckon with since 1999. Quickly gaining popularity he became a name every rager spoke about. People loved him and the powerful sets that he always delivered.Been played alongside mighty names such as Carl Cox, Dixon, Oliver Huntemann, Eric Prydz, Nina Kraviz, B2B with Maceo Plex and on big stages like Supersonic, Sunburn, Enchanted Valley Carnival, Krank, Awakenings stage India etc. His doors to Europe opened with warm welcoming hugs. Being the unstoppable force that is, he goes aheadsmashing the floors of Paradiso (Amsterdam), Feel Festival (Berlin), Ritter Butzke (Berlin) Awakenings Festival Afterparty (Amsterdam) and many more.

Also as an Owner of Rage Entertainment , he is out there to make music spoken about religion. One of the most booked DJs in India and the only Indian Dj to play the Ellum audio showcase as an Ellum dj in April in Goa')
