  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Elli Acula', 'elli acula', false, 'ELLI ACULA’s meteoric ascent is unstoppable, just like her power behind the decks & in her productions to fuse groovy, powerful sounds ranging from Techno, Rave, Breakbeat, Electro and Jungle. Her electric energy has already thrilled dancers at Europe’s top venues like Berghain, Printworks, Fabric London, Fuse Brussels and Robert Johnson, as well as dance floors in South America, Korea and Australia. However, playing late night/early morning extended vinyl sets at Berlin haunts like OHM or ://aboutblank was where she cut her teeth.

Having been a founding member of the label SPANDAU20 and creative director, it was her first release on the label that set her up for what came next. “To The Peak”, the record she made with FJAAK & Ostgut Ton’s Steffi, hits just as hard as one of ELLI ACULA’s lauded DJ sets and was immediately picked up and supported by Techno & Electro’s greatest. Her latest Release „Pleasure“ on Fabric Records further underlines her versatility as an artist and sets dance floors around the world ablaze.', 'https://www.awakenings.com/en/artists/elli-acula/249485/', 'festival:awakenings-festival-2026', 'ELLI ACULA’s meteoric ascent is unstoppable, just like her power behind the decks & in her productions to fuse groovy, powerful sounds ranging from Techno, Rave, Breakbeat, Electro and Jungle. Her electric energy has already thrilled dancers at Europe’s top venues like Berghain, Printworks, Fabric London, Fuse Brussels and Robert Johnson, as well as dance floors in South America, Korea and Australia. However, playing late night/early morning extended vinyl sets at Berlin haunts like OHM or ://aboutblank was where she cut her teeth.

Having been a founding member of the label SPANDAU20 and creative director, it was her first release on the label that set her up for what came next. “To The Peak”, the record she made with FJAAK & Ostgut Ton’s Steffi, hits just as hard as one of ELLI ACULA’s lauded DJ sets and was immediately picked up and supported by Techno & Electro’s greatest. Her latest Release „Pleasure“ on Fabric Records further underlines her versatility as an artist and sets dance floors around the world ablaze.')
