  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Marrøn', 'marrøn', false, 'Continuously trying to exceed his own limits, MARRØN employs fast rhythmics inspired by his roots. The artist’s moniker pays homage to the strong-willed MARRØN''s, a once-enslaved African tribe who defied oppression and found freedom in the primeval forests of Surinam. The hypnotic, percussive beats characterizing MARRØN’s foundational Afro Deep style have evolved to form a singular conception of techno. His dynamic take on the genre is at home in the underground, most notably in his role as co-founder and resident of Amsterdam’s EERSTE COMMUNIE. MARRØN’s capable command of groove, power, and texture is no doubt a convincing invitation to stay on the dancefloor for hours.', 'https://www.awakenings.com/en/artists/marrøn/57517/', 'festival:awakenings-festival-2026', 'Continuously trying to exceed his own limits, MARRØN employs fast rhythmics inspired by his roots. The artist’s moniker pays homage to the strong-willed MARRØN''s, a once-enslaved African tribe who defied oppression and found freedom in the primeval forests of Surinam. The hypnotic, percussive beats characterizing MARRØN’s foundational Afro Deep style have evolved to form a singular conception of techno. His dynamic take on the genre is at home in the underground, most notably in his role as co-founder and resident of Amsterdam’s EERSTE COMMUNIE. MARRØN’s capable command of groove, power, and texture is no doubt a convincing invitation to stay on the dancefloor for hours.')
