  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('BIANKA', 'bianka', false, 'Drawing from her Venezuelan roots and a lifetime of deep cultural musical exploration, BIANKA sincerely invites her listeners to share their vulnerability with her through dance. Her sets are directly inspired from her upbringing and environment - navigating the line of reality and escapism. Through textures, rhythms and intricate soundscapes, she balances different contrasts—dark meets uplifting, eerie meets warm—creating deeply emotional experiences that evolve with her ever-growing artistry.

Based in Amsterdam, BIANKA’s music is a deliberate fusion of minimal layers, deep yet driving, hypnotic techno, enriched with subtle yet unmistakable nostalgic touches of Latin American rhythms and drums. Growing up immersed in the vibrant sounds of LATAM culture, she developed a natural rhythmic instinct that informs her ability to surprise and inspire through thoughtful and deeply personal track selections. Her sound pays homage to the ''00s and ''10s while staying unafraid to explore the boundaries of forward thinking electronic music, and throwing the occasional curveball with other sub-genres. 

BIANKA has played at iconic clubs like Bret, BASIS, Perron and Nachbar, as well as at renowned events such as Intercell and Into the Woods festival and ADE. Whether delivering intricate layers or striking simplicity, BIANKA creates a space where yearning dance is coloured with deep tones of curiosity, connection and hope.', 'https://www.awakenings.com/en/artists/bianka/386597/', 'festival:awakenings-festival-2026', 'Drawing from her Venezuelan roots and a lifetime of deep cultural musical exploration, BIANKA sincerely invites her listeners to share their vulnerability with her through dance. Her sets are directly inspired from her upbringing and environment - navigating the line of reality and escapism. Through textures, rhythms and intricate soundscapes, she balances different contrasts—dark meets uplifting, eerie meets warm—creating deeply emotional experiences that evolve with her ever-growing artistry.

Based in Amsterdam, BIANKA’s music is a deliberate fusion of minimal layers, deep yet driving, hypnotic techno, enriched with subtle yet unmistakable nostalgic touches of Latin American rhythms and drums. Growing up immersed in the vibrant sounds of LATAM culture, she developed a natural rhythmic instinct that informs her ability to surprise and inspire through thoughtful and deeply personal track selections. Her sound pays homage to the ''00s and ''10s while staying unafraid to explore the boundaries of forward thinking electronic music, and throwing the occasional curveball with other sub-genres. 

BIANKA has played at iconic clubs like Bret, BASIS, Perron and Nachbar, as well as at renowned events such as Intercell and Into the Woods festival and ADE. Whether delivering intricate layers or striking simplicity, BIANKA creates a space where yearning dance is coloured with deep tones of curiosity, connection and hope.')
