  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Zisko', 'zisko', false, 'Zisko is an Argentinian artist based in Buenos Aires. His musical journey began during his childhood by learning the drums, then he gradually moved towards electronic music until he made it his favorite medium of artistic expression. He quickly stood out for his boundless creativity, his pronounced musical intuition and his ability to connect with his audience to make him travel in his musical universe for one night. Nowadays, as a DJ and producer recognized all over the world, he is one of the most popular artists of the new generation.

After signing tracks and EPs on prestigious labels such as: Suara, Uncage, MATERIA, BCCO, Bipolar Disorder, Gomboc Records and Mutual Rytm, he will release his first vinyl EP on Drawner Records label in 2023. His music is supported by DVS1, Luke Slater, Truncate, Chris Liebing, Ben Sims, Raffaele Attanasio, Marco Bailey, Laurent Garnier, Josh Wink, Rene Wise etc.

His performances are frequently noticed and acclaimed, such as those of his last European tour at Kilometer 25 (Paris), Lehmann (Stuttgart), Gotec (Karlsruhe) or even in South America at Tango (Asunción) or Crobar Club (Buenos Aires).', 'https://www.awakenings.com/en/artists/zisko/361959/', 'festival:awakenings-festival-2026', 'Zisko is an Argentinian artist based in Buenos Aires. His musical journey began during his childhood by learning the drums, then he gradually moved towards electronic music until he made it his favorite medium of artistic expression. He quickly stood out for his boundless creativity, his pronounced musical intuition and his ability to connect with his audience to make him travel in his musical universe for one night. Nowadays, as a DJ and producer recognized all over the world, he is one of the most popular artists of the new generation.

After signing tracks and EPs on prestigious labels such as: Suara, Uncage, MATERIA, BCCO, Bipolar Disorder, Gomboc Records and Mutual Rytm, he will release his first vinyl EP on Drawner Records label in 2023. His music is supported by DVS1, Luke Slater, Truncate, Chris Liebing, Ben Sims, Raffaele Attanasio, Marco Bailey, Laurent Garnier, Josh Wink, Rene Wise etc.

His performances are frequently noticed and acclaimed, such as those of his last European tour at Kilometer 25 (Paris), Lehmann (Stuttgart), Gotec (Karlsruhe) or even in South America at Tango (Asunción) or Crobar Club (Buenos Aires).')
