  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mac Declos', 'mac declos', false, 'Mac Declos is a French, Paris-based artist, DJ, and producer of electronic music. With a brilliant sound that defies expectations, Mac Declos quickly became known for his intense, precise, and technical technosets: he’s a natural. His ability to blend men-tal and physical grooves with such finesse sets him apart as a virtuoso, a master of his craft.In Spring 2024, Mac Declos dropped «Endless Cycle,» his new pulsating EP on XX Lab. It features six club-ready tracks that encapsulate Mac’s never-ending musical journey into the heart of the clubbing experience. Prior to «Endless Cycle,»Mac showcased his skills with previous releases that garnered widespread acclaim. His 2022 EP«Cuir en Cage» on Myst and his first full-lengthLP, the 10-track «Hard Work Always Pays Off,»released on Mama Told Ya in 2023, demonstrated his knack for captivating audiences. Collaborations with artists like Anetha, FrançoisX, Kuss, and Lacchesi further emphasized his multifaceted talent and influence in the music scene, cementing his status as a rising star. Mac Declos is far more than just a DJ and producer—he’s a phenomenon. With a masterful command of rhythm and groove, combined with a fearless curiosity and genre-fluid approach, he’s one of the most exciting DJs to experience on the dance floor. He evokes a joyful yet frenetic vitality, transforming every set into an unforgettable high-energy experience and solidifying his role as a defining force in the future of techno.', 'https://www.awakenings.com/en/artists/mac-declos/361880/', 'festival:awakenings-festival-2026', 'Mac Declos is a French, Paris-based artist, DJ, and producer of electronic music. With a brilliant sound that defies expectations, Mac Declos quickly became known for his intense, precise, and technical technosets: he’s a natural. His ability to blend men-tal and physical grooves with such finesse sets him apart as a virtuoso, a master of his craft.In Spring 2024, Mac Declos dropped «Endless Cycle,» his new pulsating EP on XX Lab. It features six club-ready tracks that encapsulate Mac’s never-ending musical journey into the heart of the clubbing experience. Prior to «Endless Cycle,»Mac showcased his skills with previous releases that garnered widespread acclaim. His 2022 EP«Cuir en Cage» on Myst and his first full-lengthLP, the 10-track «Hard Work Always Pays Off,»released on Mama Told Ya in 2023, demonstrated his knack for captivating audiences. Collaborations with artists like Anetha, FrançoisX, Kuss, and Lacchesi further emphasized his multifaceted talent and influence in the music scene, cementing his status as a rising star. Mac Declos is far more than just a DJ and producer—he’s a phenomenon. With a masterful command of rhythm and groove, combined with a fearless curiosity and genre-fluid approach, he’s one of the most exciting DJs to experience on the dance floor. He evokes a joyful yet frenetic vitality, transforming every set into an unforgettable high-energy experience and solidifying his role as a defining force in the future of techno.')
