  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Locus Error', 'locus error', false, 'Dutch DJ Locus Error is a fast-growing name in the Dutch techno community. Her recent and upcoming highlights include: Sisyphos (Berlin), Awakenings, Loveland, Intercell, Drift, Thuishaven, Rotterdam Rave, Soenda, Nachtcollege, BASIS and her residency for Planet Rose.

Her fascination with techno music arose as a raver herself. Dancing she felt how techno can be something dynamic that takes a raver in hypnosis through the night. Fascinated by this feeling she took to DJing herself, understanding perfectly how the waves of the dance floor form.

Her artistic journey started at a young age playing the cello as a solo performer and in (classical)orchestras, learning about music at an institute in Belgium where she graduated from a 10 year program. This knowledge about the swell, dynamics and emotions of(classical)music you can still hear in her well-crafted and musical sets.

Besides DJing, Locus Error is co-boss of BALANS record and events she runs together with Tripeo. She supports nightlife in Nijmegen by being a board member of ‘Stichting Nachtburgemeester’ and she took a great part in crafting the first DJ and producer student association in the Netherlands.', 'https://www.awakenings.com/en/artists/locus-error/277224/', 'festival:awakenings-festival-2026', 'Dutch DJ Locus Error is a fast-growing name in the Dutch techno community. Her recent and upcoming highlights include: Sisyphos (Berlin), Awakenings, Loveland, Intercell, Drift, Thuishaven, Rotterdam Rave, Soenda, Nachtcollege, BASIS and her residency for Planet Rose.

Her fascination with techno music arose as a raver herself. Dancing she felt how techno can be something dynamic that takes a raver in hypnosis through the night. Fascinated by this feeling she took to DJing herself, understanding perfectly how the waves of the dance floor form.

Her artistic journey started at a young age playing the cello as a solo performer and in (classical)orchestras, learning about music at an institute in Belgium where she graduated from a 10 year program. This knowledge about the swell, dynamics and emotions of(classical)music you can still hear in her well-crafted and musical sets.

Besides DJing, Locus Error is co-boss of BALANS record and events she runs together with Tripeo. She supports nightlife in Nijmegen by being a board member of ‘Stichting Nachtburgemeester’ and she took a great part in crafting the first DJ and producer student association in the Netherlands.')
