  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Joseph Capriati', 'joseph capriati', false, 'Since almost 20 Years into his career as a globally touring DJ, there''s hardly anaccolade Joseph Capriati hasn''t achieved. He is deservedly one of worldwide House and Techno''s scene most in-demand headliners and continues to better himself as an artist. He shows off his eclectic skills with important productions through the years on labels like CLR, Drumcode, Nervous Records, Bush Records, Kompakt or Soma. He also gave birth to his three LP''s: "Save My Soul" came out on Analytic Trail in2010, "Self Portrait" published on Drumcode in 2012 and "Metamorfosi" released in2020 on his own label Redimension Music established in 2016. He made massive remixes and collabs with iconic artists like Carl Cox, Adam Beyer, Danny Tenaglia, Joey Beltram, DJ Pierre, Louie Vega and his mentors Rino Cerrone and Markantonio of course. Nowadays Joseph Capriati is constantly focused on his calling more than ever making every release and performance a special one for his fans.', 'https://www.awakenings.com/en/artists/joseph-capriati/748/', 'festival:awakenings-festival-2026', 'Since almost 20 Years into his career as a globally touring DJ, there''s hardly anaccolade Joseph Capriati hasn''t achieved. He is deservedly one of worldwide House and Techno''s scene most in-demand headliners and continues to better himself as an artist. He shows off his eclectic skills with important productions through the years on labels like CLR, Drumcode, Nervous Records, Bush Records, Kompakt or Soma. He also gave birth to his three LP''s: "Save My Soul" came out on Analytic Trail in2010, "Self Portrait" published on Drumcode in 2012 and "Metamorfosi" released in2020 on his own label Redimension Music established in 2016. He made massive remixes and collabs with iconic artists like Carl Cox, Adam Beyer, Danny Tenaglia, Joey Beltram, DJ Pierre, Louie Vega and his mentors Rino Cerrone and Markantonio of course. Nowadays Joseph Capriati is constantly focused on his calling more than ever making every release and performance a special one for his fans.')
