  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Kara Okay', 'kara okay', false, 'Introducing Kara Okay Music (@kara.okay.music); Known for creating euphoric, up-tempo tracks, he blends ''90s trance with piano, vocals, and old school sounds. After a knee injury last year, he renewed his focus on music, producing several tracks and EP''s, which got supported by Job Jobse, DJ Heartstring, Gerd Janson, Marlon Hofstad, Malugi, Benwal, Girls Don''t Sync, Peggy Gou and others. Throughout his sets you can expect a journey through warm progressive vibes, that moves into a blend of garage, hard house and energetic, happy close-outs.', 'https://www.awakenings.com/en/artists/kara-okay/386612/', 'festival:awakenings-festival-2026', 'Introducing Kara Okay Music (@kara.okay.music); Known for creating euphoric, up-tempo tracks, he blends ''90s trance with piano, vocals, and old school sounds. After a knee injury last year, he renewed his focus on music, producing several tracks and EP''s, which got supported by Job Jobse, DJ Heartstring, Gerd Janson, Marlon Hofstad, Malugi, Benwal, Girls Don''t Sync, Peggy Gou and others. Throughout his sets you can expect a journey through warm progressive vibes, that moves into a blend of garage, hard house and energetic, happy close-outs.')
