  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Mischluft', 'mischluft', false, 'Mischluft is a Leipzig-based DJ/Producer who has burst onto the scene with hit after hit release. He is ready to seduce any crowd with his deep knowledge of groovy, ravey, and raunchy tracks. A true master behind the decks, Mischluft’s sets will romance even the most hardened techno hearts. Taking influence from the underground as well as his dad''s secret Shania Twain albums - he bridged the gap between vocal-focused trance and bouncy techno grooves.', 'https://www.awakenings.com/en/artists/mischluft/378764/', 'festival:awakenings-festival-2026', 'Mischluft is a Leipzig-based DJ/Producer who has burst onto the scene with hit after hit release. He is ready to seduce any crowd with his deep knowledge of groovy, ravey, and raunchy tracks. A true master behind the decks, Mischluft’s sets will romance even the most hardened techno hearts. Taking influence from the underground as well as his dad''s secret Shania Twain albums - he bridged the gap between vocal-focused trance and bouncy techno grooves.')
