    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Prospa', 'prospa', false, 'Since the release of their debut single ''Prayer,'' Prospa have embarked on a rapid ascent to consolidate their status as one of the UK''s most exciting electronic acts. Synthesising the true sound of euphoria in all guises, the duo are experts at crafting dancefloor focused sonics as much as they are revelling in more heartfelt, meditative moments, with the outer reaches of this versatility being broadened from release to release. Prospa showcase their sonic tapestry of high octane club sounds, blissful euphoria, and a modern interpretation of classic house music.', 'https://www.awakenings.com/en/artists/prospa/381928/', 'festival:awakenings-festival-2026', 'Since the release of their debut single ''Prayer,'' Prospa have embarked on a rapid ascent to consolidate their status as one of the UK''s most exciting electronic acts. Synthesising the true sound of euphoria in all guises, the duo are experts at crafting dancefloor focused sonics as much as they are revelling in more heartfelt, meditative moments, with the outer reaches of this versatility being broadened from release to release. Prospa showcase their sonic tapestry of high octane club sounds, blissful euphoria, and a modern interpretation of classic house music.')
