  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Josh Baker', 'josh baker', false, 'Hailing from Manchester, UK, Josh Baker has risen as a versatile DJ and producer, embodying the creative essence of the new wave of electronic artists, of which he sits at the forefront. His fascination with House music ignited at 17, propelling him to shape his passion into a thriving career.

His drive and unique talent has lead to performances at world renowned events & venues such as;The Warehouse Project, DC10, Fabric, FUSE, Shelter NL, Koko, Parklife Festival Pikes, and more, expanding his influence beyond performance venues.

In 2015, he curated the inaugural You&Me event, swiftly becoming a celebrated underground sensation, coupled with the establishment of a far-reaching music label. Not confined to You&Me''s success, Josh established the flourishing Hide&Seek Festival. His deep immersion in the scene reflects his profound connection to its culture, hinting at further exciting endeavors ahead.Its safe to say, Josh has created his own path in the underground music scene, a path only going one way..', 'https://www.awakenings.com/en/artists/josh-baker/361304/', 'festival:awakenings-festival-2026', 'Hailing from Manchester, UK, Josh Baker has risen as a versatile DJ and producer, embodying the creative essence of the new wave of electronic artists, of which he sits at the forefront. His fascination with House music ignited at 17, propelling him to shape his passion into a thriving career.

His drive and unique talent has lead to performances at world renowned events & venues such as;The Warehouse Project, DC10, Fabric, FUSE, Shelter NL, Koko, Parklife Festival Pikes, and more, expanding his influence beyond performance venues.

In 2015, he curated the inaugural You&Me event, swiftly becoming a celebrated underground sensation, coupled with the establishment of a far-reaching music label. Not confined to You&Me''s success, Josh established the flourishing Hide&Seek Festival. His deep immersion in the scene reflects his profound connection to its culture, hinting at further exciting endeavors ahead.Its safe to say, Josh has created his own path in the underground music scene, a path only going one way..')
