  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Kettama', 'kettama', false, 'We''re all well aware at this stage of the quick rise to prominence that has bestowed Galway native KETTAMA. He rose through the tricky ranks of the Irish electronic music scene through multiple residencies on the West and East coasts, all while his music''s online presence quickly caught fire across a range of different music groups online. What has happened since has been nothing short of breathtaking; his blend of hefty kicks with catchy riffs and stabs has given the house world a new ''one to watch'' and he has certainly given everyone a good show to look at thus far.', 'https://www.awakenings.com/en/artists/kettama/368898/', 'festival:awakenings-festival-2026', 'We''re all well aware at this stage of the quick rise to prominence that has bestowed Galway native KETTAMA. He rose through the tricky ranks of the Irish electronic music scene through multiple residencies on the West and East coasts, all while his music''s online presence quickly caught fire across a range of different music groups online. What has happened since has been nothing short of breathtaking; his blend of hefty kicks with catchy riffs and stabs has given the house world a new ''one to watch'' and he has certainly given everyone a good show to look at thus far.')
