  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Niiomi', 'niiomi', false, 'Niiomi is a world citizen, which you can hear in her music. Her sound is highly inspired by her Cuban/Dutch roots, whilst growing up in Zürich, Switzerland and having a Lebanese stepdad. She calls the cities Amsterdam, Zürich & Dubai home.

She fuses Afrohouse & Tech, Tribal, Melodic Electronic with Latin & Oriental influences. That''s how Niiomi brings people of different backgrounds and music preferences together.

Because of her background as professional dancer and 10 years of experience in the entertainment & Fashion industry, Niiomi knows how to enlighten her audience with the right blend of music and gets everybody to dance. Niiomi introduced her sound to the world with her debut single "Gemini" featuring the talented vocalist Idd Aziz.', 'https://www.awakenings.com/en/artists/niiomi/386517/', 'festival:awakenings-festival-2026', 'Niiomi is a world citizen, which you can hear in her music. Her sound is highly inspired by her Cuban/Dutch roots, whilst growing up in Zürich, Switzerland and having a Lebanese stepdad. She calls the cities Amsterdam, Zürich & Dubai home.

She fuses Afrohouse & Tech, Tribal, Melodic Electronic with Latin & Oriental influences. That''s how Niiomi brings people of different backgrounds and music preferences together.

Because of her background as professional dancer and 10 years of experience in the entertainment & Fashion industry, Niiomi knows how to enlighten her audience with the right blend of music and gets everybody to dance. Niiomi introduced her sound to the world with her debut single "Gemini" featuring the talented vocalist Idd Aziz.')
