  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('SHE/HER', 'she/her', false, 'Kim, also known as SHE/HER, is a techno DJ from ’s-Hertogenbosch in The Netherlands.She started DJing in 2020, drawing early inspiration from the Dutch underground (illegal) scene. Over the years she developed a style that can be described as powerful, rolling and focused on movement and energy. She plays with rhythm and progression, building momentum that carries through the set. 

Kim holds a residency at Vulged in Amsterdam and has played for venues and organisations such as Vault Sessions, Bret, Radion, Into the Woods, Basis, Intercell, along with various others.', 'https://www.awakenings.com/en/artists/she-her/386449/', 'festival:awakenings-festival-2026', 'Kim, also known as SHE/HER, is a techno DJ from ’s-Hertogenbosch in The Netherlands.She started DJing in 2020, drawing early inspiration from the Dutch underground (illegal) scene. Over the years she developed a style that can be described as powerful, rolling and focused on movement and energy. She plays with rhythm and progression, building momentum that carries through the set. 

Kim holds a residency at Vulged in Amsterdam and has played for venues and organisations such as Vault Sessions, Bret, Radion, Into the Woods, Basis, Intercell, along with various others.')
