  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Len Faki', 'len faki', false, 'His move to Berlin marked a decisive turning-point in his career. With Len Series he founded an independent platform and trademark for his idea of Techno music. The basic concept including sublabels allows him to explore musical depths and artistic freedom.  His strong appearances at venues like Tresor and Ostgut (Berlin) culminated in his residency at Berghain (the former Ostgut), a position which further fueled his open-minded approach as both DJ and producer. The characteristic extra-long DJ sets force him to vary in tone, style and feed him with extra inspiration.  At Berghain, he also launched the Podium night, a quarterly event where he invites his appreciated colleagues from all over the world. This step also resulted in the birth of his sublabel Podium with releases by Raudive (aka Oliver Ho) or Shinedoe. Right with his first offshoot, he stormed the cases and charts of top DJs/producers such as Luke Slater, Sven V..th and Ivan Smagghe.  While figure sees his own releases in loose combination with artist’s remixes, Podium features exclusive artist releases in combination with his own work. Whereas figure is like heavy tropical rain, Podium appears like a sharply defined sky after the downpour. Both labels stand for cutting-edge Techno music.  His bone-dry but communicative DJ style marks him as a true gentleman behind the turntable, an artist whose sets are based on passion and beauty. His finger tips are like sensors on the Richter scale, and anticipate as well as trigger eruptions on the floor...', 'https://www.awakenings.com/en/artists/len-faki/870/', 'festival:awakenings-festival-2026', 'His move to Berlin marked a decisive turning-point in his career. With Len Series he founded an independent platform and trademark for his idea of Techno music. The basic concept including sublabels allows him to explore musical depths and artistic freedom.  His strong appearances at venues like Tresor and Ostgut (Berlin) culminated in his residency at Berghain (the former Ostgut), a position which further fueled his open-minded approach as both DJ and producer. The characteristic extra-long DJ sets force him to vary in tone, style and feed him with extra inspiration.  At Berghain, he also launched the Podium night, a quarterly event where he invites his appreciated colleagues from all over the world. This step also resulted in the birth of his sublabel Podium with releases by Raudive (aka Oliver Ho) or Shinedoe. Right with his first offshoot, he stormed the cases and charts of top DJs/producers such as Luke Slater, Sven V..th and Ivan Smagghe.  While figure sees his own releases in loose combination with artist’s remixes, Podium features exclusive artist releases in combination with his own work. Whereas figure is like heavy tropical rain, Podium appears like a sharply defined sky after the downpour. Both labels stand for cutting-edge Techno music.  His bone-dry but communicative DJ style marks him as a true gentleman behind the turntable, an artist whose sets are based on passion and beauty. His finger tips are like sensors on the Richter scale, and anticipate as well as trigger eruptions on the floor...')
