    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('FJAAK', 'fjaak', false, 'From a Spandau-Basement experiment to a now well established force in contemporary techno: The rise of the smoked out musicians that go by the name of FJAAK has been nothing short of spectacular so far.With eleven singles & EPs, two albums and a couple of compilation appearances under their belt, FJAAK can look back on a large discography (compared to their still relatively young ages) that packs quite a punch. Easily moving through House, Techno, Rave, Ambient & Breakbeat, one can only wonder what the trio will release next. The only thing guaranteed: It will always move a dancefloor.Clubs of this world are familiar with FJAAK. They’ve taken their pulverizing live show across the whole world and played in every club worth mentioning. Their strong Instagram (possibly the best in the game) has lifted them onto the radar of every weed head on the planet, making sure every show is packed out.The Boys have readied their second album and are now focused on building their crew. Spandau20, their new project, aims to bring the community around them to the big stages that are already familiar with FJAAK, and will encompass both parties and new releases, but unlike the records that came out on their eponymous label, this time they’ll showcase fresh talent they’ve groomed for some time now. 2020 is set to be the year of Spandau20!', 'https://www.awakenings.com/en/artists/fjaak/488/', 'festival:awakenings-festival-2026', 'From a Spandau-Basement experiment to a now well established force in contemporary techno: The rise of the smoked out musicians that go by the name of FJAAK has been nothing short of spectacular so far.With eleven singles & EPs, two albums and a couple of compilation appearances under their belt, FJAAK can look back on a large discography (compared to their still relatively young ages) that packs quite a punch. Easily moving through House, Techno, Rave, Ambient & Breakbeat, one can only wonder what the trio will release next. The only thing guaranteed: It will always move a dancefloor.Clubs of this world are familiar with FJAAK. They’ve taken their pulverizing live show across the whole world and played in every club worth mentioning. Their strong Instagram (possibly the best in the game) has lifted them onto the radar of every weed head on the planet, making sure every show is packed out.The Boys have readied their second album and are now focused on building their crew. Spandau20, their new project, aims to bring the community around them to the big stages that are already familiar with FJAAK, and will encompass both parties and new releases, but unlike the records that came out on their eponymous label, this time they’ll showcase fresh talent they’ve groomed for some time now. 2020 is set to be the year of Spandau20!')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  -- ⚠ BIO FLAG: contains festival name 'Awakenings'
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Dax J', 'dax j', false, 'There are few artists carving out a legacy for themselves like Dax J is right now. The London-born DJ and producer has gone from pirate radio to magazine covers; from the backroom parties to headlining raves at every major techno institution the world over, and all whilst staying true to the underground and his individual style of raw and uncompromising techno. His mix of pure passion and attention to high-end sound production has placed him at the forefront of a global scene, and established him as a singular presence within modern dance music.
Recent accolades for his unswerving devotion to his sound have included places in the top 100 DJs polls published by Resident Advisor, DJ Mag and Groove Magazine. Over the years, he’s also received nominations as Best Techno DJ, Best Breakthrough DJ and Best British DJ from Mixmag, DJ Mag and the DJ Awards. He''s renowned for playing mammoth closing sets at monumental parties including Awakenings for ADE in the infamous Gashouder, and a 10-hour marathon set in the world’s most notorious techno club, Berghain.
Also known as a prolific producer and successful record label boss, his trademark sound remains in constant rotation among the most respected DJs in dance music. It’s a style that has evolved over many years, but which was first fully recognised on his highly acclaimed 2015 album, "Shades of Black". Upon its initial release on his own Monnom Black label, Mixmag named it "Album of the Month", Hardwax described it as “brilliantly banging” and it also took the coveted No.1 spot on Juno Records. 2018 saw Dax release his multi-faceted second solo album “Of- fending Public Morality”. The record won support across the board, including that of BBC Radio 1 who picked it as their “Biggest Record of the Week”. By the end of 2018, “Offending Public Morality” also featured in the “Top 50 Albums of the Year” lists for DJ Mag, Tsugi and Apoca- lypse Mag. Two more events that crowned a year of great success were his enrolment into the BBC hall of fame with the release of his debut Radio 1 Essential Mix, and Be.At.TV’s choice of his 4-hour closing set at NeoPop Festival for their “Best DJ set of the year”.', 'https://www.awakenings.com/en/artists/dax-j/328/', 'festival:awakenings-festival-2026', 'There are few artists carving out a legacy for themselves like Dax J is right now. The London-born DJ and producer has gone from pirate radio to magazine covers; from the backroom parties to headlining raves at every major techno institution the world over, and all whilst staying true to the underground and his individual style of raw and uncompromising techno. His mix of pure passion and attention to high-end sound production has placed him at the forefront of a global scene, and established him as a singular presence within modern dance music.
Recent accolades for his unswerving devotion to his sound have included places in the top 100 DJs polls published by Resident Advisor, DJ Mag and Groove Magazine. Over the years, he’s also received nominations as Best Techno DJ, Best Breakthrough DJ and Best British DJ from Mixmag, DJ Mag and the DJ Awards. He''s renowned for playing mammoth closing sets at monumental parties including Awakenings for ADE in the infamous Gashouder, and a 10-hour marathon set in the world’s most notorious techno club, Berghain.
Also known as a prolific producer and successful record label boss, his trademark sound remains in constant rotation among the most respected DJs in dance music. It’s a style that has evolved over many years, but which was first fully recognised on his highly acclaimed 2015 album, "Shades of Black". Upon its initial release on his own Monnom Black label, Mixmag named it "Album of the Month", Hardwax described it as “brilliantly banging” and it also took the coveted No.1 spot on Juno Records. 2018 saw Dax release his multi-faceted second solo album “Of- fending Public Morality”. The record won support across the board, including that of BBC Radio 1 who picked it as their “Biggest Record of the Week”. By the end of 2018, “Offending Public Morality” also featured in the “Top 50 Albums of the Year” lists for DJ Mag, Tsugi and Apoca- lypse Mag. Two more events that crowned a year of great success were his enrolment into the BBC hall of fame with the release of his debut Radio 1 Essential Mix, and Be.At.TV’s choice of his 4-hour closing set at NeoPop Festival for their “Best DJ set of the year”.')
