  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Fiene', 'fiene', false, 'Named fierce, dreamy and ruthless by 3 Voor 12, Fiene is one to watch. Surprising you with what you’ve never heard of, or reminding you of what you’ve always loved: Fiene seamlessly blends genres through oldschool sounds and new takes on the oldschool with influences from acid, trance, hardgroove and hardhouse. Effortlessly adapting to the vibe while sticking to what she loves most, Fiene’s sets flow with groove, feeling or simply raw energy.

Before playing at clubs and festivals, Fiene was no stranger to the scene. A strong desire tosee the artists she loved preform made her a familiar face on the dance floor ever since she was 15. With a deeply rooted passion for music that goes beyond genre or BPM, it’s no surprise she’s started producing her own tracks behinds the scenes.

You might have caught her playing at events like Intercell, Soenda, Thuishaven or By TheCreek. Haven’t had the pleasure yet? No worries, with events like Awakenings ADE, Teletech x Free Your Mind ADE and Into The Woods Festival coming up, there will be plenty of opportunities to see Fiene play in the near future', 'https://www.awakenings.com/en/artists/fiene/378542/', 'festival:awakenings-festival-2026', 'Named fierce, dreamy and ruthless by 3 Voor 12, Fiene is one to watch. Surprising you with what you’ve never heard of, or reminding you of what you’ve always loved: Fiene seamlessly blends genres through oldschool sounds and new takes on the oldschool with influences from acid, trance, hardgroove and hardhouse. Effortlessly adapting to the vibe while sticking to what she loves most, Fiene’s sets flow with groove, feeling or simply raw energy.

Before playing at clubs and festivals, Fiene was no stranger to the scene. A strong desire tosee the artists she loved preform made her a familiar face on the dance floor ever since she was 15. With a deeply rooted passion for music that goes beyond genre or BPM, it’s no surprise she’s started producing her own tracks behinds the scenes.

You might have caught her playing at events like Intercell, Soenda, Thuishaven or By TheCreek. Haven’t had the pleasure yet? No worries, with events like Awakenings ADE, Teletech x Free Your Mind ADE and Into The Woods Festival coming up, there will be plenty of opportunities to see Fiene play in the near future')
