  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Fatima Hajji', 'fatima hajji', false, 'She’s been going around with her suitcases all over Spain since 1998 and for the last few years she`s set herself up to one of the Iberian Techno representations all over Europe, not only for her dj sets but also for her own music productions.A devastating, clean, fun and dancing Hard Techno and a very high connection with her public, are her two most important keys to understand what’s going on for the last few years, where Hajji’s sound means party sound.A festive atmosphere, which can also be found in her Amitta’s sets, where she makes her own Techno performances, always true to her unique and genuine style. It’s Soft Techno but with her characteristic quality and power technique and her music selection touch.Fatima is Hard, Amitta is Soft, Hajji will always be Techno.Some festivals:AWAKENINGS, DECIBEL, FREE YOUR MIND (Holanda), TOMORROWLAND, LIBERTY WHITE (Bélgica), TOXICATOR, ELECTRIC CITY (Alemania), MONEGROS, ELECTROBEACH, AQUASELLA, ELECTROSONIC, TECHNOFLASH, WOMAD (España), ECO FESTIVAL (Eslovenia).A never ending list of clubs has welcomed her sets, some of them as legendary as:España: Florida 135, Fabrik, Row 14, Industrial Copera, Albeniz, Tecnolove, Family, La Riviera, Arena, Soma....Portugal: Big Cansil, 114 Club, Swing, Consolado (Oporto), Alcantara Mar (Lisboa), Fuel Techno (Coimbra)....Alemania: Tresor (Berlin), U60311 (Frankfurt), Ambulance (Colonia), Dance Palace (Koblenz)Italia: Int3rno (Florencia), Twisted (Napoles), Cube (Udine)Republica Checa: Roxy (Praga), Stare Lazne (Kolin), Pig Fest (Pilsen), Faval (Brno)Belgica: Het Entrepot (Brujas)Bulgaria: 4km Party Center (Sofia)Hungria: M47 (Sarand)Venezuela: Technomachines (Bogota), Back in The House (Puerto Cabello)Eslovenia: Simfonija (Planina), Extreme (Kranj)Irlanda: Midnight Court Yard (Cork), Fibber Magees (Dublin)Andorra: Play, Ambit (La Massana)', 'https://www.awakenings.com/en/artists/fatima-hajji/478/', 'festival:awakenings-festival-2026', 'She’s been going around with her suitcases all over Spain since 1998 and for the last few years she`s set herself up to one of the Iberian Techno representations all over Europe, not only for her dj sets but also for her own music productions.A devastating, clean, fun and dancing Hard Techno and a very high connection with her public, are her two most important keys to understand what’s going on for the last few years, where Hajji’s sound means party sound.A festive atmosphere, which can also be found in her Amitta’s sets, where she makes her own Techno performances, always true to her unique and genuine style. It’s Soft Techno but with her characteristic quality and power technique and her music selection touch.Fatima is Hard, Amitta is Soft, Hajji will always be Techno.Some festivals:AWAKENINGS, DECIBEL, FREE YOUR MIND (Holanda), TOMORROWLAND, LIBERTY WHITE (Bélgica), TOXICATOR, ELECTRIC CITY (Alemania), MONEGROS, ELECTROBEACH, AQUASELLA, ELECTROSONIC, TECHNOFLASH, WOMAD (España), ECO FESTIVAL (Eslovenia).A never ending list of clubs has welcomed her sets, some of them as legendary as:España: Florida 135, Fabrik, Row 14, Industrial Copera, Albeniz, Tecnolove, Family, La Riviera, Arena, Soma....Portugal: Big Cansil, 114 Club, Swing, Consolado (Oporto), Alcantara Mar (Lisboa), Fuel Techno (Coimbra)....Alemania: Tresor (Berlin), U60311 (Frankfurt), Ambulance (Colonia), Dance Palace (Koblenz)Italia: Int3rno (Florencia), Twisted (Napoles), Cube (Udine)Republica Checa: Roxy (Praga), Stare Lazne (Kolin), Pig Fest (Pilsen), Faval (Brno)Belgica: Het Entrepot (Brujas)Bulgaria: 4km Party Center (Sofia)Hungria: M47 (Sarand)Venezuela: Technomachines (Bogota), Back in The House (Puerto Cabello)Eslovenia: Simfonija (Planina), Extreme (Kranj)Irlanda: Midnight Court Yard (Cork), Fibber Magees (Dublin)Andorra: Play, Ambit (La Massana)')
