  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Isabel Soto', 'isabel soto', false, 'Isabel Soto is a Venezuelan-born, Berlin-based DJ and producer with a flair for creating one-of-a-kind experiences on the dance floor.
Her story began in Canada, where she started developing her style while exploring Montreal’s underground scene — a space that shaped her raw, hypnotic, percussive sound and gave her the freedom to experiment.

Her music is about creating a space, a feeling. Abstract textures and deep rhythms come together in her mixes and productions, guiding listeners on an atmospheric journey that feels both personal and infinite. Isabel’s sets are driven by a powerful energy that stays with you long after the last track fades.

With her own label, NYXII Records, and releases on respected imprints, including her debut EP on Ostgut Ton, Isabel is doing things her way — organically, steadily, and with real heart. Her rise isn’t about hype; it’s about the connections she creates, one track, one set, one night at a time.', 'https://www.awakenings.com/en/artists/isabel-soto/386520/', 'festival:awakenings-festival-2026', 'Isabel Soto is a Venezuelan-born, Berlin-based DJ and producer with a flair for creating one-of-a-kind experiences on the dance floor.
Her story began in Canada, where she started developing her style while exploring Montreal’s underground scene — a space that shaped her raw, hypnotic, percussive sound and gave her the freedom to experiment.

Her music is about creating a space, a feeling. Abstract textures and deep rhythms come together in her mixes and productions, guiding listeners on an atmospheric journey that feels both personal and infinite. Isabel’s sets are driven by a powerful energy that stays with you long after the last track fades.

With her own label, NYXII Records, and releases on respected imprints, including her debut EP on Ostgut Ton, Isabel is doing things her way — organically, steadily, and with real heart. Her rise isn’t about hype; it’s about the connections she creates, one track, one set, one night at a time.')
