  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Vladimir Dubyshkin', 'vladimir dubyshkin', false, 'Hailing from the ancient Russian city of Tambov, on the banks of the Tsna River, the youngest member of the Trip family is Vladimir Dubyshkin.
Vladimir Dubyshkin – an electronic producer from Russia, who doesn''t limit his musical fantasy. He loves to experiment with genres, so he is equally attractive both to lovers of noise electronics and to those who go to parties to simply dance.
Having released his debut album "Tell Me Why Its Always The Same" in February 2015, Dubyshkin quickly gained the recognition of his colleagues. In the same year he took part in two compilations on Nina Kraviz''s label "трип" and later released his first solo EP "Cheerful Pessimist".', 'https://www.awakenings.com/en/artists/vladimir-dubyshkin/75578/', 'festival:awakenings-festival-2026', 'Hailing from the ancient Russian city of Tambov, on the banks of the Tsna River, the youngest member of the Trip family is Vladimir Dubyshkin.
Vladimir Dubyshkin – an electronic producer from Russia, who doesn''t limit his musical fantasy. He loves to experiment with genres, so he is equally attractive both to lovers of noise electronics and to those who go to parties to simply dance.
Having released his debut album "Tell Me Why Its Always The Same" in February 2015, Dubyshkin quickly gained the recognition of his colleagues. In the same year he took part in two compilations on Nina Kraviz''s label "трип" and later released his first solo EP "Cheerful Pessimist".')
