  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Akua', 'akua', false, 'Akua is a Ghanaian-American DJ with roots in North American techno, but exemplifies a sonic force that reverberates worldwide. She’s cemented herself as one of the most distinctive techno DJs coming out of the U.S. in recent years, shining brightly at the forefront of a new generation of techno artists who are reviving the innovative and rebellious spirit of techno’s enduring velocity through their work. Her practice is a passionate dedication to archiving & activating timeless strains of raw and mechanized expression - leading the new school of North American machine funk, while harkening back to the revolutionary sonics of Detroit, Chicago, & New York City DJs throughout history. A recent move to Berlin, a city that has held a crucial role in the evolution of techno, has provided her with the opportunity to further develop her craft by embracing the transcontinental connection that originally ignited the inspiration for the techno movement worldwide.

Her one-of-kind, no-nonsense style brings a necessary & poignant intensity to today’s dance floors, eschewing trends of the moment and channeling the essence of techno into an authentic wavelength that’s completely intuitive to her being. This unique display of influences plays out in Akua''s unrivaled sets heard around the world - from exerting her celebrated prowess behind the decks at renowned New York clubs like Basement and Nowadays, to unleashing landmark sets at legendary institutions including Berghain, Movement Detroit, FUSE Brussels, Dekmantel, Draaimolen, & FOLD. Already seasoned on the European tour circuit, 2024 sees her career encompassing new trajectories & widening her global reach into tours through Asia & Australia.

With a wealth of knowledge and expertise, she effortlessly embodies an enthralling old-school sound while keeping her finger on the pulse of contemporary producers that also embody the authentic energy of techno’s turn-of-the-century peak. As her boundless legacy expands each year, she continues to cultivate respect and adoration from the most discerning of DJs & dancers alike through her incredible mixing finesse and constantly expanding repertoire of futureproof classics.', 'https://www.awakenings.com/en/artists/akua/285398/', 'festival:awakenings-festival-2026', 'Akua is a Ghanaian-American DJ with roots in North American techno, but exemplifies a sonic force that reverberates worldwide. She’s cemented herself as one of the most distinctive techno DJs coming out of the U.S. in recent years, shining brightly at the forefront of a new generation of techno artists who are reviving the innovative and rebellious spirit of techno’s enduring velocity through their work. Her practice is a passionate dedication to archiving & activating timeless strains of raw and mechanized expression - leading the new school of North American machine funk, while harkening back to the revolutionary sonics of Detroit, Chicago, & New York City DJs throughout history. A recent move to Berlin, a city that has held a crucial role in the evolution of techno, has provided her with the opportunity to further develop her craft by embracing the transcontinental connection that originally ignited the inspiration for the techno movement worldwide.

Her one-of-kind, no-nonsense style brings a necessary & poignant intensity to today’s dance floors, eschewing trends of the moment and channeling the essence of techno into an authentic wavelength that’s completely intuitive to her being. This unique display of influences plays out in Akua''s unrivaled sets heard around the world - from exerting her celebrated prowess behind the decks at renowned New York clubs like Basement and Nowadays, to unleashing landmark sets at legendary institutions including Berghain, Movement Detroit, FUSE Brussels, Dekmantel, Draaimolen, & FOLD. Already seasoned on the European tour circuit, 2024 sees her career encompassing new trajectories & widening her global reach into tours through Asia & Australia.

With a wealth of knowledge and expertise, she effortlessly embodies an enthralling old-school sound while keeping her finger on the pulse of contemporary producers that also embody the authentic energy of techno’s turn-of-the-century peak. As her boundless legacy expands each year, she continues to cultivate respect and adoration from the most discerning of DJs & dancers alike through her incredible mixing finesse and constantly expanding repertoire of futureproof classics.')
