  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('GHXST Bunny', 'ghxst bunny', false, 'GHXST Bunny is a Cape Town-based DJ and cultural producer originally from Butterworth, Eastern Cape. Known for her stylish flair and eclectic sound, she discovered her love for AmaPiano while studying at the University of Johannesburg, where the vibrant Soweto scene shaped her artistry.

To sharpen her skills, she joined the Bridges for Music Talent Development Programme, where she gained confidence behind the decks, explored event management, deepened her technical knowledge, and connected with a network of creatives. Highlights of her journey with Bridges include interviewing Gordo, DJing for Msaki at their gala dinner, performing at Bazique Festival, working on PR & Media for Cotton Festival, serving as artist liaison at Reforest Festival, being a FAME Week representative, producing my own show called Kwelinye iCala on The Other Radio with Bridges alumni and MCing the MixMag Lab session feat Zakes Bantwini.

Beyond the booth, GHXST Bunny is the co-founder of #PrettyGirlsLikeEvents, a womxn-centric platform that creates space for underrepresented voices in music and culture. Its signature serie #PrettyGirlsLikeKlubhouse (spotlighting womxn DJs) and #PrettyGirlsLikeFilm (celebrating womxn in film)—continue to champion womxn tastemakers across industries.

With her ability to blend genres seamlessly and curate powerful experiences, GHXST Bunny is fast becoming one of the most exciting voices in South Africa’s music and cultural scene.', 'https://www.awakenings.com/en/artists/ghxst-bunny/396293/', 'festival:awakenings-festival-2026', 'GHXST Bunny is a Cape Town-based DJ and cultural producer originally from Butterworth, Eastern Cape. Known for her stylish flair and eclectic sound, she discovered her love for AmaPiano while studying at the University of Johannesburg, where the vibrant Soweto scene shaped her artistry.

To sharpen her skills, she joined the Bridges for Music Talent Development Programme, where she gained confidence behind the decks, explored event management, deepened her technical knowledge, and connected with a network of creatives. Highlights of her journey with Bridges include interviewing Gordo, DJing for Msaki at their gala dinner, performing at Bazique Festival, working on PR & Media for Cotton Festival, serving as artist liaison at Reforest Festival, being a FAME Week representative, producing my own show called Kwelinye iCala on The Other Radio with Bridges alumni and MCing the MixMag Lab session feat Zakes Bantwini.

Beyond the booth, GHXST Bunny is the co-founder of #PrettyGirlsLikeEvents, a womxn-centric platform that creates space for underrepresented voices in music and culture. Its signature serie #PrettyGirlsLikeKlubhouse (spotlighting womxn DJs) and #PrettyGirlsLikeFilm (celebrating womxn in film)—continue to champion womxn tastemakers across industries.

With her ability to blend genres seamlessly and curate powerful experiences, GHXST Bunny is fast becoming one of the most exciting voices in South Africa’s music and cultural scene.')
