  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Athie Umgido', 'athie umgido', false, 'Athie Umgido is a South African Music Award–winning DJ, producer, founder of BFM Records, and co-founder of Umgido Records, blending Afro House, Afro-Tech, and melodic electronic music into immersive sets connecting African rhythm with the European underground dance scene.', 'https://www.awakenings.com/en/artists/athie-umgido/396290/', 'festival:awakenings-festival-2026', 'Athie Umgido is a South African Music Award–winning DJ, producer, founder of BFM Records, and co-founder of Umgido Records, blending Afro House, Afro-Tech, and melodic electronic music into immersive sets connecting African rhythm with the European underground dance scene.')
