  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('VE/RA', 've/ra', false, 'VE/RA is one of techno’s most electrifying new talents, known for her high-energy sets and relentless, driving sound.

Her breakout moment came with Love & Peace, a collaboration with Rocketman that hit #1 on the Beatport Hype Charts and gained support from Charlotte de Witte, Amelie Lens, Adam Beyer, and more. Later on, she made her Drumcode debut with Can’t Get Enough, followed by Hypnotized on Codex, Dance Therapy on Filth On Acid, Shouldn''t know on Arcane and No One Else on Exhale.

On stage, VE/RA has already played at Tomorrowland, EDC Mexico, Mysteryland, Parookaville, R2, Thuishaven, Ritter Butzke, and more.

With an unstoppable drive and a growing catalog of explosive releases, VE/RA is a name to watch in techno.', 'https://www.awakenings.com/en/artists/ve-ra/386588/', 'festival:awakenings-festival-2026', 'VE/RA is one of techno’s most electrifying new talents, known for her high-energy sets and relentless, driving sound.

Her breakout moment came with Love & Peace, a collaboration with Rocketman that hit #1 on the Beatport Hype Charts and gained support from Charlotte de Witte, Amelie Lens, Adam Beyer, and more. Later on, she made her Drumcode debut with Can’t Get Enough, followed by Hypnotized on Codex, Dance Therapy on Filth On Acid, Shouldn''t know on Arcane and No One Else on Exhale.

On stage, VE/RA has already played at Tomorrowland, EDC Mexico, Mysteryland, Parookaville, R2, Thuishaven, Ritter Butzke, and more.

With an unstoppable drive and a growing catalog of explosive releases, VE/RA is a name to watch in techno.')
