  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Amber Broos', 'amber broos', false, 'Amber Broos is a young DJ/producer from Belgium with a true passion for music. She grew up in a family of musicians and learnt the love for (retro) Techno from a very early age on. With her own monthly show on Tomorrowland’s official radio station One World Radio and as a resident for the Belgian leading radio Studio Brussel she makes her audience forget that she is only twenty years old. Her style is unique: a combination of club, retro and techno masterfully mixed and attuned to the audience. 

With stand-out performances at major festivals like Tomorrowland (Mainstage), Ushuaïa Ibiza (with Paul Kalkbrenner), Untold Festival Romania, WKND Festival Finland & Rock Werchter to name a few, she proved to be one of the rising talents on the Belgian music scene. renowned for her energetic style and happy dance vibes on stage.

Now fully focused on producing music and further evolving her own sound, Amber made her debut on Tomorrowland’s record label Tomorrowland Music in May 2023 with her release ‘Amok’. With a first performance on Tomorrowland’s Mainstage coming up in July 2023, Amber is an upcoming star that’s here to stay, ready to set festivals and dancefloors around the globe on fire and have her music heard by fans across the world!', 'https://www.awakenings.com/en/artists/amber-broos/285599/', 'festival:awakenings-festival-2026', 'Amber Broos is a young DJ/producer from Belgium with a true passion for music. She grew up in a family of musicians and learnt the love for (retro) Techno from a very early age on. With her own monthly show on Tomorrowland’s official radio station One World Radio and as a resident for the Belgian leading radio Studio Brussel she makes her audience forget that she is only twenty years old. Her style is unique: a combination of club, retro and techno masterfully mixed and attuned to the audience. 

With stand-out performances at major festivals like Tomorrowland (Mainstage), Ushuaïa Ibiza (with Paul Kalkbrenner), Untold Festival Romania, WKND Festival Finland & Rock Werchter to name a few, she proved to be one of the rising talents on the Belgian music scene. renowned for her energetic style and happy dance vibes on stage.

Now fully focused on producing music and further evolving her own sound, Amber made her debut on Tomorrowland’s record label Tomorrowland Music in May 2023 with her release ‘Amok’. With a first performance on Tomorrowland’s Mainstage coming up in July 2023, Amber is an upcoming star that’s here to stay, ready to set festivals and dancefloors around the globe on fire and have her music heard by fans across the world!')
