  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Charlotte de Witte', 'charlotte de witte', false, '“I love the darkness you find in electronic music,” explains de Witte, “especially within Techno. I find melancholic music so much more interesting and dark sounding Techno really attracts me. When I look at the main stages of some of the world''s most famous festivals and I see everyone dancing to this commercial, happy music, I don''t really understand it.”“Dark music contains much more emotion. When I’m DJ’ing I want to try and touch the crowd and tell a story with the music. Of course I want them to party, get loose and have fun but at the same time I want them to remember the music long after the lights go up.”Growing up with Belgium’s rich history of Electronic de Witte would discover Electro and Techno in her teens and was soon captivated by the hypnotic sounds she heard in the clubs around Ghent. By the age of 17 she had already made her debut behind the decks and her aggressive Techno sets soon caught the ears of some of Belgium’s biggest promoters, earning de Witte prime sets at festivals such as Pukkelpop, I Love Techno, Dour and Tomorrowland.Today de Witte can include parties and festivals in the US, South Africa and all across Europe on her CV. Still her heart remains tied to the both the underground Techno scene and Belgium where she can be found championing new talent both on her Saturday night radio show, ‘Playground Charlotte de Witte’ on Studio Brussels, Belgium’s leading radio station, and at KNTXT de Witte’s new residency at Brussels Techno institution Fuse.Having moved into production de Witte has wasted no time in establishing herself as a serious talent in the studio as well as behind the decks. But whilst a Charlotte de Witte DJ set is guaranteed to get you moving, Charlotte’s own music has provided her with a chance to reveal another side. “Making music really gives me a chance to tap into the more emotional side of electronic music that I love. Music that has that melancholic side to it, I just find it so much more interesting, whether DJ’ing, producing or just listening myself at home.” Her debut release as Charlotte de Witte on Tiga’s Turbo Recordings received called “Weltschmerz EP” gained massive national and internatonal support. Same goes for her Trip EP, released on OFF Recordings, which got featured in Ben Klock''s Mixmag CD. For now, her upcoming releases, her ongoing radio show, Fuse residency and a packed tour diary de Witte shows no sign of slowing down. Despite her love of all things dark, the future for Charlotte de Witte looks very bright indeed.', 'https://www.awakenings.com/en/artists/charlotte-de-witte/240/', 'festival:awakenings-festival-2026', '“I love the darkness you find in electronic music,” explains de Witte, “especially within Techno. I find melancholic music so much more interesting and dark sounding Techno really attracts me. When I look at the main stages of some of the world''s most famous festivals and I see everyone dancing to this commercial, happy music, I don''t really understand it.”“Dark music contains much more emotion. When I’m DJ’ing I want to try and touch the crowd and tell a story with the music. Of course I want them to party, get loose and have fun but at the same time I want them to remember the music long after the lights go up.”Growing up with Belgium’s rich history of Electronic de Witte would discover Electro and Techno in her teens and was soon captivated by the hypnotic sounds she heard in the clubs around Ghent. By the age of 17 she had already made her debut behind the decks and her aggressive Techno sets soon caught the ears of some of Belgium’s biggest promoters, earning de Witte prime sets at festivals such as Pukkelpop, I Love Techno, Dour and Tomorrowland.Today de Witte can include parties and festivals in the US, South Africa and all across Europe on her CV. Still her heart remains tied to the both the underground Techno scene and Belgium where she can be found championing new talent both on her Saturday night radio show, ‘Playground Charlotte de Witte’ on Studio Brussels, Belgium’s leading radio station, and at KNTXT de Witte’s new residency at Brussels Techno institution Fuse.Having moved into production de Witte has wasted no time in establishing herself as a serious talent in the studio as well as behind the decks. But whilst a Charlotte de Witte DJ set is guaranteed to get you moving, Charlotte’s own music has provided her with a chance to reveal another side. “Making music really gives me a chance to tap into the more emotional side of electronic music that I love. Music that has that melancholic side to it, I just find it so much more interesting, whether DJ’ing, producing or just listening myself at home.” Her debut release as Charlotte de Witte on Tiga’s Turbo Recordings received called “Weltschmerz EP” gained massive national and internatonal support. Same goes for her Trip EP, released on OFF Recordings, which got featured in Ben Klock''s Mixmag CD. For now, her upcoming releases, her ongoing radio show, Fuse residency and a packed tour diary de Witte shows no sign of slowing down. Despite her love of all things dark, the future for Charlotte de Witte looks very bright indeed.')
