  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Lisa Korver', 'lisa korver', false, 'Lisa Korver is a DJ and producer whose sound moves effortlessly between Latincore, Trance, Hard Groove and adjacent club territories -always driven by an unmistakable sense of groove and momentum. Her sets are defined by contrast and control, balancing intensity with musicality, and have earned her a growing reputation both within the Netherlands and beyond.

Alongside performances at influential events such as Lowlands, Into the Woods and Soenda, Lisa’s productions have played a key role in shaping her profile. Tracks like Dale Duro, Like That and Focal underline her ability to translate high-energy club dynamics into distinctive, forward-facing releases that resonate on dancefloors as well as online.

With a clear artistic vision, an expanding catalogue of releases and an increasingly visible presence on major festival line-ups, Lisa Korver has established herself as one of the defining artists in the current Dutch electronic music landscape, continuing to push her sound while steadily expanding her international reach.', 'https://www.awakenings.com/en/artists/lisa-korver/386618/', 'festival:awakenings-festival-2026', 'Lisa Korver is a DJ and producer whose sound moves effortlessly between Latincore, Trance, Hard Groove and adjacent club territories -always driven by an unmistakable sense of groove and momentum. Her sets are defined by contrast and control, balancing intensity with musicality, and have earned her a growing reputation both within the Netherlands and beyond.

Alongside performances at influential events such as Lowlands, Into the Woods and Soenda, Lisa’s productions have played a key role in shaping her profile. Tracks like Dale Duro, Like That and Focal underline her ability to translate high-energy club dynamics into distinctive, forward-facing releases that resonate on dancefloors as well as online.

With a clear artistic vision, an expanding catalogue of releases and an increasingly visible presence on major festival line-ups, Lisa Korver has established herself as one of the defining artists in the current Dutch electronic music landscape, continuing to push her sound while steadily expanding her international reach.')
