  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('LAMMER', 'lammer', false, 'LAMMER is an emerging force in the high-energy dance music scene, based in Rotterdam, Netherlands. His dynamic sound has quickly captured the attention of industry tastemakers such as Job Jobse, Benwal and Trym, placing him firmly on the radar.

Renowned for his electrifying DJ sets, LAMMER has proven his ability to captivate audiences, whether in intimate underground venues or on grandfestival stages. With a background in art and a deep dive into music
production during his studies, his creative journey extends beyond music, shaping his vision for the visual elements surrounding his work.

Following the success of his highly anticipated first original release ‘All Nightʼ, LAMMER is now focusing on his productions, determined to leave a lasting imprint on the scene in 2025. His sound, heavily inspired by 90s rave, trance and house music, is infused with a euphoric energy that creates a unforgettable experience for his listeners. With his captivating DJ performances and standout productions, LAMMER is quickly becoming a rising artist, gaining traction across Europe and
captivating crowds with every set.', 'https://www.awakenings.com/en/artists/lammer/368201/', 'festival:awakenings-festival-2026', 'LAMMER is an emerging force in the high-energy dance music scene, based in Rotterdam, Netherlands. His dynamic sound has quickly captured the attention of industry tastemakers such as Job Jobse, Benwal and Trym, placing him firmly on the radar.

