  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Bad Boombox', 'bad boombox', false, 'Bad Boombox recently emerged with an irreverence and colorful vitality rarely seen intechno.
Bad Boombox is a Bulgarian-American DJ who has been a recent formidable force inthe techno scene. Known for his incredibly original DJ dance moves on stage (such asAir-fisting and the Queen Glizzy™), he is a juggernaut in the industry-once coming inthird place in a Jason Derulo remix contest in 2013. After gaining dozens of followers onTiktok, Bad Boombox ventured into starting his own record label, fashion brand, andtotally legal massage clinic. He is also known to have kissed on the mouth at least sixtimes.', 'https://www.awakenings.com/en/artists/bad-boombox/386076/', 'festival:awakenings-festival-2026', 'Bad Boombox recently emerged with an irreverence and colorful vitality rarely seen intechno.
Bad Boombox is a Bulgarian-American DJ who has been a recent formidable force inthe techno scene. Known for his incredibly original DJ dance moves on stage (such asAir-fisting and the Queen Glizzy™), he is a juggernaut in the industry-once coming inthird place in a Jason Derulo remix contest in 2013. After gaining dozens of followers onTiktok, Bad Boombox ventured into starting his own record label, fashion brand, andtotally legal massage clinic. He is also known to have kissed on the mouth at least sixtimes.')
  ON CONFLICT (sort_name) DO UPDATE SET
