  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Partiboi69', 'partiboi69', false, 'Spiritual leader, Icon, Prophet – that''s for others to say. Partiboi69''s only objective is to spread digital love and deliver lethal 69 techniques live and direct to your senses. Described on the Internet as “symbol of mutual love and mystery of the Australian underground,” Partiboi69 is as advertised, without compromise. CEO of Mutual Pleasure record and Stingboi Productions, Partiboi69 fuses cutting edge, computer animated graphics with the sounds of ElectroDank, Ghetto Freak and K-Tech, to create a portal into his complex mind; A place where comfort and style are paramount, no stimulant is safe, and enjoyment is always mutual. The most explicit samplings of this are “Freaky Dreamz”, “Magnificent” and “Freaking You Out”, as well as his technologically-advanced live mix broadcasts, as visually pleasurable as they are aurally – much like 69ing.', 'https://www.awakenings.com/en/artists/partiboi69/288725/', 'festival:awakenings-festival-2026', 'Spiritual leader, Icon, Prophet – that''s for others to say. Partiboi69''s only objective is to spread digital love and deliver lethal 69 techniques live and direct to your senses. Described on the Internet as “symbol of mutual love and mystery of the Australian underground,” Partiboi69 is as advertised, without compromise. CEO of Mutual Pleasure record and Stingboi Productions, Partiboi69 fuses cutting edge, computer animated graphics with the sounds of ElectroDank, Ghetto Freak and K-Tech, to create a portal into his complex mind; A place where comfort and style are paramount, no stimulant is safe, and enjoyment is always mutual. The most explicit samplings of this are “Freaky Dreamz”, “Magnificent” and “Freaking You Out”, as well as his technologically-advanced live mix broadcasts, as visually pleasurable as they are aurally – much like 69ing.')
