  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Easttown', 'easttown', false, 'Dutch DJ & Producer Easttown is one of the fastest-rising talents in the global house music scene. Based in Amsterdam, his sound blends infectious disco elements with a 90’s house vibe, creating a unique style that’s been catching attention across the globe. His tracks have already found their way into the playlists of DJs like Seth Troxler, Folamour, Avalon Emerson, Joseph Capriati, ANOTR, Dennis Cruz, and Jamie Jones, with his music regularly gracing the stages of iconic events like Circoloco and Dekmantel. In 2024, Easttown made his mark with multiple (vinyl) EP releases on respected labels such as Cécille, Folamour’s House of Love, and Franky Rizardo’s LTF label. These releases helped establish him in the international scene. Known for his high-energy DJ sets, Easttown has played at renowned venues and festivals, including Strafwerk Festival, Music On x Loveland, Ants, Shelter (Amsterdam), Badaboum (Paris), and Elysia (Basel). With multiple new releases lined up, Easttown is set to take 2025 by storm, continuing to build his presence in the international house music scene.', 'https://www.awakenings.com/en/artists/easttown/386606/', 'festival:awakenings-festival-2026', 'Dutch DJ & Producer Easttown is one of the fastest-rising talents in the global house music scene. Based in Amsterdam, his sound blends infectious disco elements with a 90’s house vibe, creating a unique style that’s been catching attention across the globe. His tracks have already found their way into the playlists of DJs like Seth Troxler, Folamour, Avalon Emerson, Joseph Capriati, ANOTR, Dennis Cruz, and Jamie Jones, with his music regularly gracing the stages of iconic events like Circoloco and Dekmantel. In 2024, Easttown made his mark with multiple (vinyl) EP releases on respected labels such as Cécille, Folamour’s House of Love, and Franky Rizardo’s LTF label. These releases helped establish him in the international scene. Known for his high-energy DJ sets, Easttown has played at renowned venues and festivals, including Strafwerk Festival, Music On x Loveland, Ants, Shelter (Amsterdam), Badaboum (Paris), and Elysia (Basel). With multiple new releases lined up, Easttown is set to take 2025 by storm, continuing to build his presence in the international house music scene.')
