  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Franky Rizardo', 'franky rizardo', false, 'Franky Rizardo - one of The Netherlands finest exports in House and Techno established himself as a name renowned across the globe, synonymous with deep driving music that blurs the lines between Techno and House.

					A regular in Ibiza within the ANTS, Music On and Elrow camps - as well as hitting the decks in iconic venues such as Fabric (London), Shelter (Amsterdam), Amnesia (Ibiza) and Sound (Los Angeles), Franky is further cementing his status as one of electronic music’s most dynamic individuals.

					Entering 2023 - Franky Rizardo saw an expansion of his music with his own label LTF Records - hitting the no.1 on Beatport with ‘Everybody’ and ‘Out The Fire (At The Hotel’ garnering over 6 million plays on Spotify in hits first year. Launching his FLOW brand in 2015 with good friend Jasper Fioole, the pair have challenged themselves to bring people into the flow state of mind by creating vibrant gatherings and connecting people, whilst creating unique moments to ultimately result in total fulfillment. FLOW hosts over 20 events a year, including stages at festivals like Tomorrowland Festival, Extrema Outdoor and Mysteryland Festival.

					As FLOW continues to grow, 2023 will see them launch into territories such as the USA, Australia, Asia and beyond, expanding their own FLOW Freedom Festival, as well as hunting down one of a kind, unique locations for intimate gatherings.

					Here dawns an expansion of Franky’s career, with exploration into new territories, his ambition and dedication to presenting an unfiltered version of himself remains unparalleled. Always moving forward and, the Dutch artist is unlocking his true potential as a multi-faceted performer and artist.', 'https://www.awakenings.com/en/artists/franky-rizardo/288695/', 'festival:awakenings-festival-2026', 'Franky Rizardo - one of The Netherlands finest exports in House and Techno established himself as a name renowned across the globe, synonymous with deep driving music that blurs the lines between Techno and House.

					A regular in Ibiza within the ANTS, Music On and Elrow camps - as well as hitting the decks in iconic venues such as Fabric (London), Shelter (Amsterdam), Amnesia (Ibiza) and Sound (Los Angeles), Franky is further cementing his status as one of electronic music’s most dynamic individuals.

					Entering 2023 - Franky Rizardo saw an expansion of his music with his own label LTF Records - hitting the no.1 on Beatport with ‘Everybody’ and ‘Out The Fire (At The Hotel’ garnering over 6 million plays on Spotify in hits first year. Launching his FLOW brand in 2015 with good friend Jasper Fioole, the pair have challenged themselves to bring people into the flow state of mind by creating vibrant gatherings and connecting people, whilst creating unique moments to ultimately result in total fulfillment. FLOW hosts over 20 events a year, including stages at festivals like Tomorrowland Festival, Extrema Outdoor and Mysteryland Festival.

					As FLOW continues to grow, 2023 will see them launch into territories such as the USA, Australia, Asia and beyond, expanding their own FLOW Freedom Festival, as well as hunting down one of a kind, unique locations for intimate gatherings.

					Here dawns an expansion of Franky’s career, with exploration into new territories, his ambition and dedication to presenting an unfiltered version of himself remains unparalleled. Always moving forward and, the Dutch artist is unlocking his true potential as a multi-faceted performer and artist.')
