  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Kaufmann', 'kaufmann', false, 'As a child of Germany''s rave scene, Kaufmann passes on the energy she absorbed in clubs, festivals, warehouses and parties under motorway bridges. Her mix of styles, both in her releases and in her sets, ranges from Techno to Trance and is always bursting with concentrated energy and psychedelic sounds. She has been on her creative journey for over 10 years, fiddling with knobs and since 2020 putting out her own tracks. This path has led to her getting featured by dance musics biggest names and given her the opportunity to showcase her signature sound around the world.', 'https://www.awakenings.com/en/artists/kaufmann/386615/', 'festival:awakenings-festival-2026', 'As a child of Germany''s rave scene, Kaufmann passes on the energy she absorbed in clubs, festivals, warehouses and parties under motorway bridges. Her mix of styles, both in her releases and in her sets, ranges from Techno to Trance and is always bursting with concentrated energy and psychedelic sounds. She has been on her creative journey for over 10 years, fiddling with knobs and since 2020 putting out her own tracks. This path has led to her getting featured by dance musics biggest names and given her the opportunity to showcase her signature sound around the world.')
