  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Chris Avantgarde', 'chris avantgarde', false, 'Chris Avantgarde is a German born, London based artist, producer & composer best known for his off-kilter approach towards electronic production. His work includes placements in hit TV shows and blockbuster
movie trailers alike. (DARK, Lucifer, Ragnarok, Sicario 2, Birds of Prey).

His versatile approach has also made official remixes for artists like The Prodigy, Billie Eilish & Nina Simone an unprecedented possibility.

His current releases as a recording artist include culture record “Consciousness” in collaboration with Anyma, which peaked at #1 on the Beatport overall charts and has set a precedent for organic virality in the
scene.

His performances span from Techno to Electronica infused with a cinematic approach to storytelling.', 'https://www.awakenings.com/en/artists/chris-avantgarde/386471/', 'festival:awakenings-festival-2026', 'Chris Avantgarde is a German born, London based artist, producer & composer best known for his off-kilter approach towards electronic production. His work includes placements in hit TV shows and blockbuster
movie trailers alike. (DARK, Lucifer, Ragnarok, Sicario 2, Birds of Prey).

His versatile approach has also made official remixes for artists like The Prodigy, Billie Eilish & Nina Simone an unprecedented possibility.

His current releases as a recording artist include culture record “Consciousness” in collaboration with Anyma, which peaked at #1 on the Beatport overall charts and has set a precedent for organic virality in the
scene.

His performances span from Techno to Electronica infused with a cinematic approach to storytelling.')
