  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Julia Maria', 'julia maria', false, 'Julia Maria (she/her) is a DJ based in Rotterdam. She has a powerful blend of driving, compelling and hard-hitting techno. A steady balance between these soundscapes can lead to rhythmic yet powerful dj-sets from beginning till end which Julia Maria achieves to make with her music.', 'https://www.awakenings.com/en/artists/julia-maria/375465/', 'festival:awakenings-festival-2026', 'Julia Maria (she/her) is a DJ based in Rotterdam. She has a powerful blend of driving, compelling and hard-hitting techno. A steady balance between these soundscapes can lead to rhythmic yet powerful dj-sets from beginning till end which Julia Maria achieves to make with her music.')
