  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Nikolina', 'nikolina', false, 'For NIKOLINA, self-expression was always connected to music.
Raving the front row, she began to envision herself creating those moments for others. Driven by this passion, she transitioned behind the decks. With her energetic and driving style she has taken the scene by storm, captivating audiences worldwide.

Her performances are not just about playing tracks - they''re about taking the crowd on an emotional rollercoaster. She uses Schranz, with its hypnotic rhythms and robust beats, to truly touch the audience, making each set an immersive journey. This genre''s continuous, pulsating rhythm not only keeps the energy high but also allows her to connect deeply, giving her audience a powerful way to express themselves through dance.', 'https://www.awakenings.com/en/artists/nikolina/386624/', 'festival:awakenings-festival-2026', 'For NIKOLINA, self-expression was always connected to music.
Raving the front row, she began to envision herself creating those moments for others. Driven by this passion, she transitioned behind the decks. With her energetic and driving style she has taken the scene by storm, captivating audiences worldwide.

Her performances are not just about playing tracks - they''re about taking the crowd on an emotional rollercoaster. She uses Schranz, with its hypnotic rhythms and robust beats, to truly touch the audience, making each set an immersive journey. This genre''s continuous, pulsating rhythm not only keeps the energy high but also allows her to connect deeply, giving her audience a powerful way to express themselves through dance.')
