  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('BIIA', 'biia', false, 'BIIA is an electronic music artist who shows an emotional curiosity that is so mirrored in her creative process. 

She creates a journey of self-expression that blends different approaches of techno. These are energetic and hard-hitting stories that can combine raw, hard, 90’s beats and peculiar sounds with different genres occasionally popping. Her productions express music without boundaries that oozes trippy elements with screaming kicks and sectionally her provocative and conceptual vocals. 

BIIA, disruptive and unappreciative of labels, is a talent that stays true to her artistic vision.', 'https://www.awakenings.com/en/artists/biia/361877/', 'festival:awakenings-festival-2026', 'BIIA is an electronic music artist who shows an emotional curiosity that is so mirrored in her creative process. 

She creates a journey of self-expression that blends different approaches of techno. These are energetic and hard-hitting stories that can combine raw, hard, 90’s beats and peculiar sounds with different genres occasionally popping. Her productions express music without boundaries that oozes trippy elements with screaming kicks and sectionally her provocative and conceptual vocals. 

BIIA, disruptive and unappreciative of labels, is a talent that stays true to her artistic vision.')
