  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Novah', 'novah', false, 'NOVAH is a female hard techno DJ and producer based in Antwerp, Belgium. Withan international presence, she graces Europe''s most prestigious DJ booths, leaving an indelible mark on the global electronic music scene.Already making waves in the industry, Novah has released tracks with esteemed labels such as Taapion, No Mercy, Revised Records, and Teletech. Even more exciting releases are planned for this year. This milestone is just the beginning, as she continues to work on upcoming releases that are set to captivate listeners. NOVAH''s artistry knows no boundaries as she fearlessly explores a diverse range of genres, seamlessly blending elements of acid, industrial, psy-trance, and hard techno. However, what truly sets her apart is her unmatched ability to harness energy and exercise precise control, evident in every performance she delivers. Prepare to be taken on a captivating musical journey that defies expectations.', 'https://www.awakenings.com/en/artists/novah/359053/', 'festival:awakenings-festival-2026', 'NOVAH is a female hard techno DJ and producer based in Antwerp, Belgium. Withan international presence, she graces Europe''s most prestigious DJ booths, leaving an indelible mark on the global electronic music scene.Already making waves in the industry, Novah has released tracks with esteemed labels such as Taapion, No Mercy, Revised Records, and Teletech. Even more exciting releases are planned for this year. This milestone is just the beginning, as she continues to work on upcoming releases that are set to captivate listeners. NOVAH''s artistry knows no boundaries as she fearlessly explores a diverse range of genres, seamlessly blending elements of acid, industrial, psy-trance, and hard techno. However, what truly sets her apart is her unmatched ability to harness energy and exercise precise control, evident in every performance she delivers. Prepare to be taken on a captivating musical journey that defies expectations.')
