    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Reinier Zonneveld', 'reinier zonneveld', false, 'Born in the Netherlands on the 30 January 1991, Zonneveld’s introduction to music was through the classical piano lessons he began aged just three years old. Some years later he started to compose classical music pieces and performed solo piano concerts. But it was only after attending his first illegal raves while studying at university that the artist we know today began exploring electronic music production. Spending all of his student allowances on his first synthesizers, he managed to teach himself his outstanding production skills in his student dorm. After completing two master''s degrees in 2015, he decided to dedicate all of his time and effort to his ever-growing passion: producing and performing techno music. Soon after, his tracks 
were already getting picked up by some of the biggest names in the scene. 
Releases quickly followed on Oliver Koletzki’s Stil vor Talent, Carl Cox’s Intec and Richie Hawtin’s Minus, as did two official remixes for electronic legend Moby. With his productions and live sets influenced by both his classical background and his own rave experiences, it’s no surprise that his sound contains an incredible breadth, ranging from deep melodic tracks to pounding warehouse acid techno. His musical talent truly shines through in his captivating live performances which see him plow through his impressive discography and tease unreleased material alike. 
He’s been known to play all-night live sets, spontaneously constructed and feeding off the energy of the dancefloor in a reciprocal synergy. Within just a few years of beginning his career, he has already performed in all continents, from main stages to underground clubs, leaving a thrilled crowd on each dancefloor. When not on the road, he works hard to find the time to create tracks and further hone his skills in the studio, with the experiences and influences gained from his performances and travels serving as a constant source of inspiration. He also runs his own acclaimed label Filth on Acid, founded in early 2017. 
The label gives him full creative control and serves as a platform for his wide view on techno music. His successes include Beatport overall No.1 smash. Things We Might Have Said, which featured on his well-received artist album Megacity Servant and was also licensed to a Hollywood production. Next to this and the numerous amount of releases from his hand, he collaborated together with Carl Cox on Filth on Acid and released two official remixes for Moby. 
It’s clear that Reinier Zonneveld will further influence today’s global techno scene with his unique productions and dancefloor-shaking live sets for years to come. 
This is just the beginning...', 'https://www.awakenings.com/en/artists/reinier-zonneveld/1282/', 'festival:awakenings-festival-2026', 'Born in the Netherlands on the 30 January 1991, Zonneveld’s introduction to music was through the classical piano lessons he began aged just three years old. Some years later he started to compose classical music pieces and performed solo piano concerts. But it was only after attending his first illegal raves while studying at university that the artist we know today began exploring electronic music production. Spending all of his student allowances on his first synthesizers, he managed to teach himself his outstanding production skills in his student dorm. After completing two master''s degrees in 2015, he decided to dedicate all of his time and effort to his ever-growing passion: producing and performing techno music. Soon after, his tracks 
were already getting picked up by some of the biggest names in the scene. 
Releases quickly followed on Oliver Koletzki’s Stil vor Talent, Carl Cox’s Intec and Richie Hawtin’s Minus, as did two official remixes for electronic legend Moby. With his productions and live sets influenced by both his classical background and his own rave experiences, it’s no surprise that his sound contains an incredible breadth, ranging from deep melodic tracks to pounding warehouse acid techno. His musical talent truly shines through in his captivating live performances which see him plow through his impressive discography and tease unreleased material alike. 
He’s been known to play all-night live sets, spontaneously constructed and feeding off the energy of the dancefloor in a reciprocal synergy. Within just a few years of beginning his career, he has already performed in all continents, from main stages to underground clubs, leaving a thrilled crowd on each dancefloor. When not on the road, he works hard to find the time to create tracks and further hone his skills in the studio, with the experiences and influences gained from his performances and travels serving as a constant source of inspiration. He also runs his own acclaimed label Filth on Acid, founded in early 2017. 
The label gives him full creative control and serves as a platform for his wide view on techno music. His successes include Beatport overall No.1 smash. Things We Might Have Said, which featured on his well-received artist album Megacity Servant and was also licensed to a Hollywood production. Next to this and the numerous amount of releases from his hand, he collaborated together with Carl Cox on Filth on Acid and released two official remixes for Moby. 
It’s clear that Reinier Zonneveld will further influence today’s global techno scene with his unique productions and dancefloor-shaking live sets for years to come. 
This is just the beginning...')
