  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Rosati', 'rosati', false, 'Rosati is an Italian DJ and techno producer based in Amsterdam, known for a sound deeply rooted in early techno traditions and reshaped through a contemporary lens. Influenced by Detroit, UK rave culture, and classic European techno, his productions balance raw groove with precision and dance-floor focus.

His music has been released on respected underground labels including Dolly, SoHaSo, Voltage, Sungate, and more recently on Clone’s in house techno label Repetitive Rhythm Research (collaboration track with Earwax). He has also released a collaborative EP with Steffi, on Dolly earning support across the international techno circuit.

Rosati performs both live sets and DJ sets, with a strong preference for vinyl, bringing a tactile, hands-on approach to the dance floor. Alongside his studio work, he runs Global Pulse, a vinyl-focused label dedicated to timeless, forward-thinking techno. Now firmly established in Amsterdam’s scene, Rosati continues to develop music that bridges techno’s past, present, and future.', 'https://www.awakenings.com/en/artists/rosati/386636/', 'festival:awakenings-festival-2026', 'Rosati is an Italian DJ and techno producer based in Amsterdam, known for a sound deeply rooted in early techno traditions and reshaped through a contemporary lens. Influenced by Detroit, UK rave culture, and classic European techno, his productions balance raw groove with precision and dance-floor focus.

His music has been released on respected underground labels including Dolly, SoHaSo, Voltage, Sungate, and more recently on Clone’s in house techno label Repetitive Rhythm Research (collaboration track with Earwax). He has also released a collaborative EP with Steffi, on Dolly earning support across the international techno circuit.

Rosati performs both live sets and DJ sets, with a strong preference for vinyl, bringing a tactile, hands-on approach to the dance floor. Alongside his studio work, he runs Global Pulse, a vinyl-focused label dedicated to timeless, forward-thinking techno. Now firmly established in Amsterdam’s scene, Rosati continues to develop music that bridges techno’s past, present, and future.')
