  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Stranger', 'stranger', false, 'Tipped as being one of Rotterdam''s best kept secrets in Techno, dj/producer ''stranger'' moves in mysterious ways and has quickly proven to be one to watch. His first musical appearance in 2014 was quickly picked up by established names as Dave Clarke, Sven Vath and Marcel Dettmann, giving his career as well as his own Self Reflektion label a major kick-start. While remaining in the background pushing forward talented artists and working on various projects such as the highly anticipated Paling Trax label, his dj-career is on the rise. His name can be found on the line-ups of some of the biggest clubs and events in techno such as Awakenings, Tresor and many others. This is not your average ''unknown artist''', 'https://www.awakenings.com/en/artists/stranger/1484/', 'festival:awakenings-festival-2026', 'Tipped as being one of Rotterdam''s best kept secrets in Techno, dj/producer ''stranger'' moves in mysterious ways and has quickly proven to be one to watch. His first musical appearance in 2014 was quickly picked up by established names as Dave Clarke, Sven Vath and Marcel Dettmann, giving his career as well as his own Self Reflektion label a major kick-start. While remaining in the background pushing forward talented artists and working on various projects such as the highly anticipated Paling Trax label, his dj-career is on the rise. His name can be found on the line-ups of some of the biggest clubs and events in techno such as Awakenings, Tresor and many others. This is not your average ''unknown artist''')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Talismann', 'talismann', false, 'For Guy Blanken, music is a matter of the heart, and a boundless playing field for sonic explorations. His compulsive curiosity has led him to unusual corners of the electronic music realm – spawning a multifaceted, yet distinctive discography. As Makam, he has investigated anything from exhilarating club anthems to contemplative downtempo moods. And as Talismann, he is probing ever deeper into the abyss of sinister soundscapes and industrial drum patterns.

When Guy hasn’t locked himself in the studio, or isn’t tending to one of his labels, he loves engaging with the dance floor during one of his tireless DJ or live sets. Finding a home at Amsterdam institutions like Trouw, and De School (the now closed down) Dekmantel has given him the opportunity and freedom to connect with fellow travelers, and continue on his fascinating musical journey. 

Talismann is Guy’s darker incarnation. From the moment he delivered tracks like‘Mars Wars’ and‘ Zula’ (2012), his take-no-prisoner approach has been indisputable. Talismann Records has cemented its position as the home of intense, inky techno and ambient. Moreover, Slagmann, his collaboration with Slagwerk Den Haag, has resulted in one of the most experimental, and arguably most intriguing albums in his oeuvre ‘Krysalis’.

Following the release of his illustrious 3-part album "PERCUSSION," Talismann boldly articulates his distinctive vision of techno. Embarking on the esteemed KLINIEK series, a nine-part EP collection, he delves into uncharted territories and boundaries to redefine the essence of late-night destress.Guy meticulously refines his unparalleled vision forged from over two decades of club expertise through the exclusive KLINIEK events, typically scheduled for Sundays. The story continues.', 'https://www.awakenings.com/en/artists/talismann/60113/', 'festival:awakenings-festival-2026', 'For Guy Blanken, music is a matter of the heart, and a boundless playing field for sonic explorations. His compulsive curiosity has led him to unusual corners of the electronic music realm – spawning a multifaceted, yet distinctive discography. As Makam, he has investigated anything from exhilarating club anthems to contemplative downtempo moods. And as Talismann, he is probing ever deeper into the abyss of sinister soundscapes and industrial drum patterns.

When Guy hasn’t locked himself in the studio, or isn’t tending to one of his labels, he loves engaging with the dance floor during one of his tireless DJ or live sets. Finding a home at Amsterdam institutions like Trouw, and De School (the now closed down) Dekmantel has given him the opportunity and freedom to connect with fellow travelers, and continue on his fascinating musical journey. 

Talismann is Guy’s darker incarnation. From the moment he delivered tracks like‘Mars Wars’ and‘ Zula’ (2012), his take-no-prisoner approach has been indisputable. Talismann Records has cemented its position as the home of intense, inky techno and ambient. Moreover, Slagmann, his collaboration with Slagwerk Den Haag, has resulted in one of the most experimental, and arguably most intriguing albums in his oeuvre ‘Krysalis’.

Following the release of his illustrious 3-part album "PERCUSSION," Talismann boldly articulates his distinctive vision of techno. Embarking on the esteemed KLINIEK series, a nine-part EP collection, he delves into uncharted territories and boundaries to redefine the essence of late-night destress.Guy meticulously refines his unparalleled vision forged from over two decades of club expertise through the exclusive KLINIEK events, typically scheduled for Sundays. The story continues.')
