  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Ares Carter', 'ares carter', false, 'Ares Carter is a DJ and producer whose career blossomed from an under-18 club residency in New York City into headlining the biggest festival stages in the world. He’s on a mission to push forward the boundaries of electronic music, armed with a freshly crafted sound aimed towards the international crowd. He started off as the official DJ for iLoveMakonnen, developing his skills as a globally touring DJ alongside the acclaimed hip- hop/pop artist. Not long after, performances at festivals like Electric Zoo NYC, Mysteryland USA, and Diplo’s Mad Decent Boat Party helped turn Ares Carter into a desirable name across the United States, giving him the opportunity to open for A-list artists such as Diplo, Kygo, Martin Garrix, and Steve Aoki. In 2019, Ares made his main stage debut at Ultra Music Festival in Japan and Korea. He took major steps into the booming Asian dance music circuit, headlining super-clubs in Seoul, Shanghai, Hong Kong, Macau, Tokyo, and various other cities throughout the region. Welcoming the dawn of a new decade, Ares has spent the last few years locked in the studio developing a new sound in both his productions and live sets, taking inspiration from all his years rooted in the dance floor. His seamless blend of house music, pop, hip hop, and underground influences is something you’ll find yourself endlessly playing on repeat — attesting to Ares Carter’s forward-thinking mentality in creating the sounds of the future.', 'https://www.awakenings.com/en/artists/ares-carter/386591/', 'festival:awakenings-festival-2026', 'Ares Carter is a DJ and producer whose career blossomed from an under-18 club residency in New York City into headlining the biggest festival stages in the world. He’s on a mission to push forward the boundaries of electronic music, armed with a freshly crafted sound aimed towards the international crowd. He started off as the official DJ for iLoveMakonnen, developing his skills as a globally touring DJ alongside the acclaimed hip- hop/pop artist. Not long after, performances at festivals like Electric Zoo NYC, Mysteryland USA, and Diplo’s Mad Decent Boat Party helped turn Ares Carter into a desirable name across the United States, giving him the opportunity to open for A-list artists such as Diplo, Kygo, Martin Garrix, and Steve Aoki. In 2019, Ares made his main stage debut at Ultra Music Festival in Japan and Korea. He took major steps into the booming Asian dance music circuit, headlining super-clubs in Seoul, Shanghai, Hong Kong, Macau, Tokyo, and various other cities throughout the region. Welcoming the dawn of a new decade, Ares has spent the last few years locked in the studio developing a new sound in both his productions and live sets, taking inspiration from all his years rooted in the dance floor. His seamless blend of house music, pop, hip hop, and underground influences is something you’ll find yourself endlessly playing on repeat — attesting to Ares Carter’s forward-thinking mentality in creating the sounds of the future.')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    bio_source = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_source ELSE artists.bio_source END,
    bio_festival = CASE WHEN EXCLUDED.bio_festival IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio_festival ELSE artists.bio_festival END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url, bio_source, bio_festival)
  VALUES ('Joyhauser', 'joyhauser', false, 'Born out of a deep passion for electronic music culture, Joyhauser is one of the most exciting, incendiary acts in the world of contemporary techno. Their music has a unique flavour, combining influences from techno, trance, Belgium’s own distinct rave lineage and a myriad of other styles. Poised to release their debut album, In Memero, the duo are entering a new phase of their evolution; driven by their core values, with an expansive vision of their destiny...
The duo named themselves after two influential psychologists; Joy Paul Guilford and Marc Hauser. Guilford’s explorations of intelligence and Hauser’s work around primate behaviour form two key pillars of Joyhauser’s inspiration. This interest in psychology provides the conceptual backbone to their debut album, In Memero.
Running across 12 tracks, In Memero demonstrates Stijn and Joris’ diverse tastes, from the sonic power of rave and techno, to lower BPMs and broken beats. In Memero will be the backbone to Joyhauser’s forthcoming live show, a further extension of their Intelligence-meets-Behaviour ethos.
As they take another step forward in their evolution, Joyhauser maintain their core ideals; imbuing their music with a truly human touch, guided by feeling, emotion and universal intelligence...', 'https://www.awakenings.com/en/artists/joyhauser/752/', 'festival:awakenings-festival-2026', 'Born out of a deep passion for electronic music culture, Joyhauser is one of the most exciting, incendiary acts in the world of contemporary techno. Their music has a unique flavour, combining influences from techno, trance, Belgium’s own distinct rave lineage and a myriad of other styles. Poised to release their debut album, In Memero, the duo are entering a new phase of their evolution; driven by their core values, with an expansive vision of their destiny...
The duo named themselves after two influential psychologists; Joy Paul Guilford and Marc Hauser. Guilford’s explorations of intelligence and Hauser’s work around primate behaviour form two key pillars of Joyhauser’s inspiration. This interest in psychology provides the conceptual backbone to their debut album, In Memero.
Running across 12 tracks, In Memero demonstrates Stijn and Joris’ diverse tastes, from the sonic power of rave and techno, to lower BPMs and broken beats. In Memero will be the backbone to Joyhauser’s forthcoming live show, a further extension of their Intelligence-meets-Behaviour ethos.
As they take another step forward in their evolution, Joyhauser maintain their core ideals; imbuing their music with a truly human touch, guided by feeling, emotion and universal intelligence...')
